import type { FlashcardData } from "./flashcards-rpn";

export const rnPathoExpansionFlashcards: FlashcardData[] = [
  // ============================================================
  // DIABETES PATHOPHYSIOLOGY (25 cards)
  // ============================================================
  { id: "rn-patho-diabetes-1", type: "question", question: "A patient with Type 1 diabetes has a C-peptide level of 0.1 ng/mL (normal 0.8-3.1). What does this indicate?", options: ["Excessive insulin production", "Near-absent endogenous insulin production from autoimmune beta-cell destruction", "Normal pancreatic function", "Insulin resistance"], correctIndex: 1, answer: "C-peptide is co-secreted with insulin from beta cells. A near-undetectable level confirms that the pancreas is producing virtually no insulin, consistent with autoimmune destruction of beta cells in T1DM. T2DM patients typically have normal or elevated C-peptide levels.", category: "Endocrine", difficulty: 2, clinicalPearl: "C-peptide is the best clinical test to distinguish T1DM (low/absent) from T2DM (normal/elevated). It reflects endogenous insulin production because it is not affected by exogenous insulin administration." },
  { id: "rn-patho-diabetes-2", type: "question", question: "Which HLA genotype confers the highest risk for developing Type 1 diabetes?", options: ["HLA-B27", "HLA-DR3/DR4 heterozygosity", "HLA-DR2", "HLA-A3"], correctIndex: 1, answer: "HLA-DR3/DR4 heterozygosity confers the highest genetic risk for T1DM, with approximately 5% lifetime risk compared to 0.4% in the general population. These HLA class II molecules present beta-cell autoantigens to T cells, initiating the autoimmune cascade.", category: "Endocrine", difficulty: 3, clinicalPearl: "HLA-B27 is associated with ankylosing spondylitis, not diabetes. HLA-DR3/DR4 is the key association for T1DM." },
  { id: "rn-patho-diabetes-3", type: "question", question: "A patient with T2DM has dark, velvety patches on the back of the neck. This finding is called:", options: ["Vitiligo", "Acanthosis nigricans", "Psoriasis", "Contact dermatitis"], correctIndex: 1, answer: "Acanthosis nigricans is a skin finding associated with insulin resistance and hyperinsulinemia. The excess insulin stimulates keratinocyte and fibroblast proliferation in skin folds. Its presence should prompt diabetes screening.", category: "Endocrine", difficulty: 1, clinicalPearl: "Acanthosis nigricans is commonly found in the neck folds, axillae, and groin. It is a visible clinical marker of insulin resistance." },
  { id: "rn-patho-diabetes-4", type: "question", question: "Which mechanism causes polyuria in uncontrolled diabetes?", options: ["Increased ADH secretion", "Osmotic diuresis from glucose exceeding the renal threshold (~180 mg/dL)", "Decreased aldosterone", "Renal tubular acidosis"], correctIndex: 1, answer: "When blood glucose exceeds the renal reabsorptive threshold of approximately 180 mg/dL, glucose spills into the urine (glycosuria). Glucose acts as an osmotic agent, pulling water into the tubular lumen, causing osmotic diuresis and polyuria.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-5", type: "question", question: "The Somogyi effect is best described as:", options: ["Morning hyperglycemia from a cortisol surge", "Rebound morning hyperglycemia caused by counter-regulatory hormone release in response to nocturnal hypoglycemia", "Afternoon hypoglycemia after lunch", "Insulin resistance worsening at night"], correctIndex: 1, answer: "The Somogyi effect occurs when a patient becomes hypoglycemic during sleep (often 2-3 AM), triggering counter-regulatory hormones (glucagon, cortisol, epinephrine) that cause rebound hyperglycemia by morning. Checking a 3 AM blood glucose differentiates this from the Dawn phenomenon.", category: "Endocrine", difficulty: 2, clinicalPearl: "Dawn phenomenon = early morning hyperglycemia from physiologic cortisol/GH surge (no nocturnal hypoglycemia). Somogyi effect = rebound hyperglycemia FROM nocturnal hypoglycemia. Check 3 AM glucose to distinguish." },
  { id: "rn-patho-diabetes-6", type: "question", question: "Which complication of diabetes results from sorbitol accumulation in the lens via the polyol pathway?", options: ["Retinopathy", "Cataracts from osmotic lens swelling", "Glaucoma", "Macular degeneration"], correctIndex: 1, answer: "In chronic hyperglycemia, excess glucose enters the polyol pathway and is converted to sorbitol by aldose reductase. Sorbitol cannot cross cell membranes and accumulates, drawing water osmotically into the lens, causing swelling and opacification (cataracts).", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-diabetes-7", type: "question", question: "A T2DM patient on metformin is scheduled for a CT scan with IV contrast. What should the nurse do?", options: ["Continue metformin as normal", "Hold metformin for 48 hours before and after the procedure", "Double the metformin dose to protect the kidneys", "Switch to insulin permanently"], correctIndex: 1, answer: "Metformin must be held 48 hours before and after IV contrast administration to prevent lactic acidosis. Contrast can cause acute kidney injury, and impaired renal clearance of metformin increases the risk of lactate accumulation.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-8", type: "question", question: "What is the 'honeymoon period' in Type 1 diabetes?", options: ["The time between diagnosis and first DKA episode", "A temporary period after diagnosis when remaining beta cells increase insulin output, reducing exogenous insulin needs", "The period when oral medications are effective", "The first year of insulin pump therapy"], correctIndex: 1, answer: "The honeymoon period occurs shortly after T1DM diagnosis when the remaining beta cells temporarily increase insulin production, sometimes dramatically reducing exogenous insulin requirements. This is NOT remission — it always ends as autoimmune destruction continues.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-9", type: "question", question: "Which insulin should NEVER be mixed with other insulins in the same syringe?", options: ["NPH insulin", "Regular insulin", "Insulin glargine (Lantus)", "Insulin lispro"], correctIndex: 2, answer: "Insulin glargine has an acidic pH (4.0) that forms microprecipitates for slow absorption. Mixing with other insulins disrupts this mechanism and alters the pharmacokinetics of both insulins. It must always be given as a separate injection.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-10", type: "question", question: "In the Rule of 15 for hypoglycemia management, what does the nurse administer?", options: ["15 units of insulin", "15g of fast-acting carbohydrate, then recheck glucose in 15 minutes", "15 mL of glucagon", "15 mg of dextrose IV push"], correctIndex: 1, answer: "The Rule of 15: give 15g of fast-acting carbohydrate (4 glucose tablets, 4 oz juice, or 1 tablespoon honey), recheck blood glucose in 15 minutes, and repeat if still below 70 mg/dL. This prevents overcorrection while treating hypoglycemia effectively.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-11", type: "question", question: "Which long-term complication screening should be performed annually for ALL diabetes patients?", options: ["Cardiac catheterization", "Dilated eye exam, urine albumin-to-creatinine ratio, and monofilament foot exam", "Brain MRI", "Bone density scan"], correctIndex: 1, answer: "Annual screening for the three major microvascular complications: diabetic retinopathy (dilated eye exam), diabetic nephropathy (urine albumin-to-creatinine ratio), and diabetic neuropathy (monofilament foot exam). Early detection allows intervention before irreversible damage occurs.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-12", type: "question", question: "SGLT2 inhibitors can cause which unusual form of DKA?", options: ["Hyperglycemic DKA", "Euglycemic DKA (ketoacidosis with near-normal blood glucose)", "Hypoglycemic DKA", "Respiratory alkalosis"], correctIndex: 1, answer: "SGLT2 inhibitors promote urinary glucose excretion, keeping blood glucose lower while the body shifts to fat metabolism for energy. This can produce ketoacidosis with near-normal glucose levels, delaying recognition of the dangerous condition.", category: "Endocrine", difficulty: 3, clinicalPearl: "If a patient on an SGLT2 inhibitor has nausea, vomiting, or malaise — check ketones even if glucose is relatively normal. Hold SGLT2 inhibitor 3-4 days before surgery." },
  { id: "rn-patho-diabetes-13", type: "question", question: "A patient with diabetes reports numbness and burning in both feet that is worse at night. This pattern is most consistent with:", options: ["Peripheral arterial disease", "Diabetic peripheral neuropathy in a stocking-glove distribution", "Lumbar radiculopathy", "Plantar fasciitis"], correctIndex: 1, answer: "Diabetic peripheral neuropathy presents as bilateral, symmetric numbness, tingling, and burning pain starting distally (feet) and progressing proximally in a 'stocking-glove' pattern. It results from chronic hyperglycemia damaging small nerve fibers through the polyol pathway and AGE formation.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-14", type: "question", question: "What is the target HbA1c for most adults with diabetes?", options: ["<5.0%", "<6.0%", "<7.0%", "<9.0%"], correctIndex: 2, answer: "The ADA recommends an HbA1c target of <7.0% for most non-pregnant adults with diabetes. More stringent targets (<6.5%) may be appropriate for younger patients, while less stringent targets (<8.0%) may be appropriate for elderly patients with comorbidities or hypoglycemia risk.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-15", type: "question", question: "Which mechanism makes metformin different from sulfonylureas?", options: ["Metformin stimulates insulin secretion from beta cells", "Metformin decreases hepatic glucose production without stimulating insulin secretion, so it does NOT cause hypoglycemia alone", "Metformin works only in Type 1 diabetes", "Metformin increases appetite"], correctIndex: 1, answer: "Metformin reduces hepatic gluconeogenesis and improves insulin sensitivity without stimulating insulin secretion. Because it does not increase insulin levels, hypoglycemia does not occur when used as monotherapy, unlike sulfonylureas which directly stimulate beta-cell insulin release.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-16", type: "question", question: "A patient asks why they need to rotate insulin injection sites. The best response is:", options: ["To reduce pain with each injection", "To prevent lipodystrophy (lipohypertrophy or lipoatrophy) which impairs insulin absorption", "Because insulin works better in different body areas", "To prevent skin infections"], correctIndex: 1, answer: "Repeated injection at the same site causes lipodystrophy — either lipohypertrophy (fatty lumps) or lipoatrophy (fat loss) — which creates an inconsistent absorption rate, leading to unpredictable glucose levels. Rotating sites within the same body region maintains consistent absorption.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-17", type: "question", question: "The 'Ominous Octet' in Type 2 diabetes refers to:", options: ["Eight types of insulin", "Eight pathophysiological defects contributing to hyperglycemia: decreased insulin secretion, increased glucagon, hepatic glucose output, decreased muscle uptake, increased lipolysis, decreased incretin effect, increased renal glucose reabsorption, CNS dysfunction", "Eight organ systems affected by diabetes", "Eight diabetic medications"], correctIndex: 1, answer: "Ralph DeFronzo described 8 concurrent pathophysiological defects in T2DM, explaining why monotherapy often fails and combination therapy targeting multiple pathways is more effective.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-diabetes-18", type: "question", question: "What is the most common adverse effect of GLP-1 receptor agonists (semaglutide)?", options: ["Hypoglycemia", "Nausea (most common — usually transient, minimized by slow dose titration)", "Hepatotoxicity", "Hyperkalemia"], correctIndex: 1, answer: "Nausea is the most common side effect of GLP-1 receptor agonists, occurring in up to 40% of patients. It is typically transient (resolving over 4-8 weeks) and minimized by starting at the lowest dose and titrating slowly. GLP-1 agonists delay gastric emptying, contributing to the nausea.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-19", type: "question", question: "A nurse is teaching sick-day rules to a Type 1 diabetes patient. Which instruction is MOST important?", options: ["Stop all insulin until you feel better", "NEVER stop basal insulin — check glucose every 2-4 hours, check ketones if glucose >250 mg/dL", "Only take insulin if you can eat a full meal", "Double all insulin doses when sick"], correctIndex: 1, answer: "Basal insulin must NEVER be stopped, even when sick or not eating. Basal insulin prevents ketogenesis and controls hepatic glucose output. During illness, counter-regulatory hormones increase glucose levels, so insulin requirements often increase. Stopping insulin leads to DKA.", category: "Endocrine", difficulty: 2, clinicalPearl: "Sick-day rules: never stop basal insulin, check glucose every 2-4 hours, check ketones if >250 mg/dL, maintain hydration, contact provider if ketones are moderate/large or glucose consistently >300." },
  { id: "rn-patho-diabetes-20", type: "question", question: "Which autoantibody is most commonly tested to confirm Type 1 diabetes?", options: ["Anti-nuclear antibody (ANA)", "Anti-GAD65 (glutamic acid decarboxylase) antibody", "Anti-dsDNA antibody", "Anti-CCP antibody"], correctIndex: 1, answer: "Anti-GAD65 is the most sensitive islet autoantibody for T1DM, present in approximately 70-80% of newly diagnosed patients. Other autoantibodies include anti-IA-2, IAA, and anti-ZnT8. The presence of 2 or more autoantibodies in at-risk individuals nearly guarantees progression to T1DM.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-21", type: "question", question: "Diabetic nephropathy is first detected by:", options: ["Elevated serum creatinine", "Microalbuminuria (urine albumin-to-creatinine ratio >30 mg/g)", "Proteinuria on urine dipstick", "Decreased urine output"], correctIndex: 1, answer: "Microalbuminuria (30-300 mg/g on UACR) is the earliest detectable sign of diabetic nephropathy, appearing years before serum creatinine rises or overt proteinuria develops. Annual screening with UACR allows early intervention with ACE inhibitors/ARBs to slow progression.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-22", type: "question", question: "Which class of diabetes medications provides the most significant cardiovascular and renal protection in T2DM?", options: ["Sulfonylureas", "SGLT2 inhibitors and GLP-1 receptor agonists", "Alpha-glucosidase inhibitors", "Thiazolidinediones"], correctIndex: 1, answer: "SGLT2 inhibitors (empagliflozin, dapagliflozin) and GLP-1 receptor agonists (semaglutide, liraglutide) have demonstrated cardiovascular mortality benefit and renal protective effects in landmark trials (EMPA-REG, LEADER, SUSTAIN-6, SELECT).", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-23", type: "question", question: "Rapid-acting insulin (lispro) should be administered:", options: ["30 minutes before meals", "Within 15 minutes of starting the meal", "At bedtime", "Only when blood glucose exceeds 300 mg/dL"], correctIndex: 1, answer: "Rapid-acting insulin analogs (lispro, aspart, glulisine) have onset within 15 minutes and peak at 1-2 hours, designed to cover postprandial glucose spikes. They should be given within 15 minutes of meal onset (before or immediately after starting to eat).", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-24", type: "question", question: "Advanced glycation end products (AGEs) contribute to diabetic complications by:", options: ["Lowering blood glucose", "Cross-linking proteins and activating inflammatory pathways through RAGE receptors, damaging blood vessel walls", "Improving insulin sensitivity", "Enhancing nerve regeneration"], correctIndex: 1, answer: "AGEs form when glucose reacts non-enzymatically with proteins (glycation). These modified proteins cross-link, altering tissue structure and function. AGEs activate RAGE receptors on endothelial cells, macrophages, and mesangial cells, triggering NF-kB-mediated inflammation, ROS production, and vascular damage.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-diabetes-25", type: "question", question: "A patient with T1DM is found unconscious with a blood glucose of 28 mg/dL. What is the priority intervention?", options: ["Administer oral glucose", "Administer IM or SC glucagon (or IV dextrose if IV access available)", "Give a glass of orange juice", "Wait for the patient to wake up"], correctIndex: 1, answer: "An unconscious patient CANNOT swallow safely — oral glucose is contraindicated due to aspiration risk. Glucagon IM/SC (or IV dextrose 25g if IV access is available) is the treatment. Glucagon stimulates hepatic glycogenolysis, raising blood glucose within 10-15 minutes.", category: "Endocrine", difficulty: 1, clinicalPearl: "Teach family members/caregivers how to administer glucagon IM. The patient should have an emergency glucagon kit at all times. After glucagon administration, turn the patient on their side (recovery position) to prevent aspiration if vomiting occurs." },

  // ============================================================
  // DKA (25 cards)
  // ============================================================
  { id: "rn-patho-dka-1", type: "question", question: "What is the FIRST intervention in DKA management?", options: ["Start insulin drip immediately", "Administer IV normal saline for fluid resuscitation", "Give oral glucose", "Administer bicarbonate"], correctIndex: 1, answer: "IV fluid resuscitation with normal saline (1-1.5 L/hour for the first 1-2 hours) is the FIRST intervention in DKA. Fluid alone reduces glucose by 35-70 mg/dL/hour through hemodilution and improved renal clearance. Insulin comes AFTER ensuring potassium is adequate.", category: "Endocrine", difficulty: 1, clinicalPearl: "Sequence: Fluids FIRST → Check potassium → Insulin AFTER K+ confirmed ≥3.3 mEq/L" },
  { id: "rn-patho-dka-2", type: "question", question: "Why must potassium be checked BEFORE starting insulin in DKA?", options: ["Insulin causes hyperkalemia", "Insulin drives potassium into cells, and if K+ is already low, this can cause fatal cardiac arrhythmias", "Potassium interferes with insulin absorption", "Insulin is incompatible with potassium solutions"], correctIndex: 1, answer: "Insulin activates Na+/K+-ATPase, driving potassium from extracellular to intracellular space. In DKA, total body potassium is depleted despite serum K+ appearing normal/elevated (acidosis shifts K+ out of cells). Starting insulin with K+ <3.3 can cause fatal hypokalemia (VFib).", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-3", type: "question", question: "Kussmaul respirations in DKA represent:", options: ["Hyperventilation from anxiety", "Respiratory compensation for metabolic acidosis — deep, rapid breathing to blow off CO2", "Obstruction from bronchospasm", "Normal breathing pattern during stress"], correctIndex: 1, answer: "Kussmaul respirations are deep, labored breaths that increase CO2 elimination to compensate for the metabolic acidosis caused by ketone body accumulation. The expected pCO2 follows Winter's formula: pCO2 = (1.5 × HCO3) + 8 ± 2.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-4", type: "question", question: "When should dextrose be added to IV fluids during DKA treatment?", options: ["When the patient feels hungry", "When blood glucose reaches 200-250 mg/dL (to prevent hypoglycemia while continuing insulin to clear ketones)", "Only after all ketones are cleared", "Dextrose should never be given in DKA"], correctIndex: 1, answer: "When glucose reaches 200-250 mg/dL, IV fluids are switched to D5-half NS and the insulin rate is reduced. Dextrose prevents hypoglycemia while insulin continues to clear the remaining ketones and close the anion gap.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-5", type: "question", question: "The anion gap in DKA is elevated because:", options: ["Chloride levels are high", "Unmeasured anions (ketone bodies: beta-hydroxybutyrate and acetoacetate) accumulate in the blood", "Sodium levels are elevated", "Bicarbonate levels are elevated"], correctIndex: 1, answer: "DKA produces a high anion gap metabolic acidosis. The ketone bodies (beta-hydroxybutyrate and acetoacetate) are unmeasured anions that increase the gap. Anion gap = Na - (Cl + HCO3); normal is 8-12. In DKA, it is typically >20.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-6", type: "question", question: "Which type of insulin can be administered intravenously?", options: ["Insulin glargine (Lantus)", "Insulin NPH", "Regular insulin (only type approved for IV use)", "Insulin detemir (Levemir)"], correctIndex: 2, answer: "Regular insulin is the ONLY insulin that can be given IV. Its soluble, clear formulation allows for immediate IV bioavailability. Long-acting and intermediate insulins (glargine, NPH, detemir) form depot preparations designed for subcutaneous absorption.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-7", type: "question", question: "The fruity breath odor in DKA is caused by:", options: ["Dehydration", "Exhaled acetone (a volatile ketone body produced during ketogenesis)", "High blood glucose", "Acidic pH of the blood"], correctIndex: 1, answer: "Acetone is a volatile ketone body produced alongside beta-hydroxybutyrate and acetoacetate. Unlike the other ketones, acetone is exhaled through the lungs, producing the characteristic fruity/nail polish remover breath odor that is a clinical hallmark of DKA.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-8", type: "question", question: "A child in DKA treatment develops sudden headache, vomiting, and decreased consciousness. The nurse should suspect:", options: ["Worsening DKA", "Cerebral edema — the most dangerous complication of DKA treatment in children", "Anxiety", "Migraine headache"], correctIndex: 1, answer: "Cerebral edema is the leading cause of DKA-related death in children. Rapid fluid administration and too-rapid glucose correction cause osmotic water shifts into brain cells. Signs include headache, vomiting, altered LOC, bradycardia, and hypertension (Cushing triad).", category: "Endocrine", difficulty: 3, clinicalPearl: "Risk factors for cerebral edema in pediatric DKA: young age, new-onset diabetes, severe acidosis, high BUN, rapid glucose correction, and large fluid volumes." },
  { id: "rn-patho-dka-9", type: "question", question: "When can the insulin drip be discontinued in DKA?", options: ["When blood glucose reaches normal levels", "When the anion gap closes AND the patient can eat, with SQ insulin overlapping the IV drip by 1-2 hours", "Immediately after blood glucose drops below 200", "After 24 hours regardless of lab values"], correctIndex: 1, answer: "The insulin drip should continue until the anion gap normalizes (indicating ketone clearance), pH >7.30, HCO3 >18, AND the patient can tolerate oral intake. SQ insulin must overlap with the IV drip by 1-2 hours to prevent rebound ketoacidosis.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-10", type: "question", question: "What is the most common precipitant of DKA?", options: ["Exercise", "Missed insulin doses or infection/illness", "Eating too much sugar", "Emotional stress alone"], correctIndex: 1, answer: "The two most common precipitants of DKA are non-adherence to insulin therapy (missed doses) and infection/acute illness. Infection triggers counter-regulatory hormone release (cortisol, glucagon), increasing insulin requirements beyond the patient's usual dose.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-11", type: "question", question: "How does HHS (Hyperosmolar Hyperglycemic State) differ from DKA?", options: ["HHS has more ketones than DKA", "HHS has extreme hyperglycemia (>600), minimal ketosis, profound dehydration, and higher mortality than DKA", "HHS only occurs in Type 1 diabetes", "HHS and DKA are identical conditions"], correctIndex: 1, answer: "HHS occurs in T2DM patients who retain enough insulin to prevent ketogenesis but not enough to prevent hyperglycemia. It develops insidiously with extreme glucose (often >600-1000), profound dehydration (8-12L deficit), hyperosmolarity (>320), and neurological dysfunction. Mortality is 10-20% vs 1-5% for DKA.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-12", type: "question", question: "Which lab value determines if insulin can be safely started in DKA?", options: ["Blood glucose level", "Serum potassium ≥3.3 mEq/L", "Arterial pH", "White blood cell count"], correctIndex: 1, answer: "Serum potassium must be ≥3.3 mEq/L before starting insulin. Insulin drives potassium intracellularly via Na+/K+-ATPase activation. Starting insulin with hypokalemia can cause fatal cardiac arrhythmias (peaked T waves → widened QRS → VFib).", category: "Endocrine", difficulty: 2, clinicalPearl: "DKA Potassium Protocol: K+ <3.3 → HOLD insulin, replace K+ aggressively; K+ 3.3-5.3 → Start insulin, add K+ to IV fluids; K+ >5.3 → Start insulin, hold K+, recheck in 2 hours." },
  { id: "rn-patho-dka-13", type: "question", question: "Bicarbonate administration in DKA is considered ONLY when:", options: ["pH drops below any level", "pH <6.9 (severe, life-threatening acidosis)", "Glucose exceeds 500 mg/dL", "The patient requests it"], correctIndex: 1, answer: "IV bicarbonate is reserved for severe, life-threatening acidosis (pH <6.9) because: (1) it can worsen intracellular acidosis paradoxically; (2) it can cause hypokalemia; (3) it shifts the oxygen dissociation curve leftward, impairing O2 delivery. Most DKA resolves with insulin and fluids alone.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-dka-14", type: "question", question: "Target glucose decrease rate during DKA treatment should be:", options: ["As fast as possible", "50-75 mg/dL per hour", "200 mg/dL per hour", "No specific target"], correctIndex: 1, answer: "Glucose should decrease at 50-75 mg/dL per hour. Too-rapid correction increases the risk of cerebral edema (especially in children) due to osmotic water shifts into brain cells. If glucose drops faster than 100 mg/dL/hour, the insulin rate should be decreased.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-15", type: "question", question: "Why does abdominal pain occur in DKA?", options: ["Liver enlargement", "Ketone-induced gastric irritation and ileus, which can mimic an acute surgical abdomen", "Appendicitis commonly co-occurs with DKA", "Abdominal pain does not occur in DKA"], correctIndex: 1, answer: "Abdominal pain in DKA results from ketone-induced gastric irritation, peritoneal irritation from acidosis, gastroparesis, and functional ileus. It can mimic acute surgical conditions (appendicitis, pancreatitis), requiring careful evaluation. Abdominal pain typically resolves with DKA treatment.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-16", type: "question", question: "Counter-regulatory hormones in DKA include all of the following EXCEPT:", options: ["Glucagon", "Insulin", "Cortisol", "Catecholamines"], correctIndex: 1, answer: "Insulin is NOT a counter-regulatory hormone — it LOWERS glucose. The counter-regulatory hormones that RAISE glucose and worsen DKA are glucagon, cortisol, catecholamines (epinephrine/norepinephrine), and growth hormone.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-17", type: "question", question: "Beta-hydroxybutyrate accounts for what percentage of ketone bodies in DKA?", options: ["25%", "50%", "75% (it is the predominant ketone in DKA)", "100%"], correctIndex: 2, answer: "Beta-hydroxybutyrate accounts for approximately 75% of ketone bodies in DKA, with acetoacetate making up most of the rest, and acetone being a minor volatile component. Standard urine ketone tests (nitroprusside reaction) detect acetoacetate but NOT beta-hydroxybutyrate, which can lead to underestimation of ketosis.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-dka-18", type: "question", question: "An appropriate fluid for DKA resuscitation after corrected sodium is assessed:", options: ["D5W", "0.9% Normal Saline initially, then adjust to 0.45% NS or D5-0.45% NS based on corrected sodium and glucose", "Lactated Ringer's", "5% Albumin"], correctIndex: 1, answer: "Initial resuscitation uses 0.9% NS (isotonic). After the first 1-2 hours, if the corrected sodium is normal or elevated, switch to 0.45% NS to provide free water. When glucose reaches 200-250, switch to D5-0.45% NS to prevent hypoglycemia.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-19", type: "question", question: "DKA most commonly occurs in which type of diabetes?", options: ["Type 2 diabetes exclusively", "Type 1 diabetes (though it can occur in Type 2 under severe stress)", "Gestational diabetes", "Pre-diabetes"], correctIndex: 1, answer: "DKA classically occurs in Type 1 diabetes due to absolute insulin deficiency. However, it can occur in Type 2 diabetes during severe physiologic stress (sepsis, MI, surgery) when counter-regulatory hormones overwhelm the remaining insulin secretion. SGLT2 inhibitors can also cause DKA in T2DM.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-20", type: "question", question: "How often should blood glucose be monitored during a DKA insulin infusion?", options: ["Every 4 hours", "Every hour", "Every 8 hours", "Only when symptoms change"], correctIndex: 1, answer: "During continuous IV insulin infusion for DKA, blood glucose must be checked HOURLY to ensure appropriate rate of decline (50-75 mg/dL/hour), prevent hypoglycemia, and determine when to add dextrose to IV fluids (when glucose reaches 200-250 mg/dL).", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-21", type: "question", question: "What is osmotic demyelination syndrome and when is it a concern in DKA?", options: ["A liver disorder", "A neurological condition that can occur if serum sodium is corrected too rapidly during treatment", "A cardiac complication", "An insulin side effect"], correctIndex: 1, answer: "Osmotic demyelination syndrome (formerly central pontine myelinolysis) can occur when serum sodium is corrected too rapidly. In DKA, corrected sodium often rises as glucose falls, and overly aggressive fluid management can inadvertently cause rapid sodium shifts.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-dka-22", type: "question", question: "The primary substrate for ketone body production in DKA is:", options: ["Glucose", "Free fatty acids released from unrestrained lipolysis in adipose tissue", "Amino acids", "Lactate"], correctIndex: 1, answer: "Without insulin's anti-lipolytic effect, adipose tissue releases massive quantities of free fatty acids (FFAs). These FFAs are transported to the liver where glucagon activates CPT-1, transporting FFAs into mitochondria for beta-oxidation, producing acetyl-CoA that is shunted to ketogenesis.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-23", type: "question", question: "Phosphate replacement in DKA is indicated when:", options: ["Phosphate is mildly low", "Serum phosphate <1.0 mg/dL (severe hypophosphatemia causing respiratory muscle weakness and hemolytic anemia)", "All DKA patients need phosphate", "Phosphate levels are not monitored in DKA"], correctIndex: 1, answer: "Severe hypophosphatemia (<1.0 mg/dL) can cause respiratory muscle weakness (worsening ventilation), hemolytic anemia (ATP depletion in RBCs), and cardiac dysfunction. Routine phosphate replacement in mild-moderate depletion is not recommended.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-dka-24", type: "question", question: "A nurse calculating the anion gap for a DKA patient: Na 138, Cl 98, HCO3 10. The anion gap is:", options: ["20", "30 (138 - 98 - 10 = 30, indicating high anion gap metabolic acidosis)", "10", "40"], correctIndex: 1, answer: "Anion gap = Na - (Cl + HCO3) = 138 - (98 + 10) = 30. Normal anion gap is 8-12. A gap of 30 indicates significant accumulation of unmeasured anions (ketone bodies) consistent with DKA. The gap must normalize before stopping the insulin drip.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-25", type: "question", question: "What percentage of children with Type 1 diabetes present with DKA as their first manifestation?", options: ["5%", "25-30%", "50%", "75%"], correctIndex: 1, answer: "Approximately 25-30% of children with new-onset Type 1 diabetes present in DKA at the time of initial diagnosis. The autoimmune destruction has progressed to a critical point where insulin deficiency causes acute metabolic decompensation before the diagnosis is recognized.", category: "Endocrine", difficulty: 2 },

  // ============================================================
  // THYROID DISEASE (25 cards)
  // ============================================================
  { id: "rn-patho-thyroid-1", type: "question", question: "Which test is the MOST sensitive screening test for thyroid dysfunction?", options: ["Free T4", "Free T3", "TSH", "Thyroid antibodies"], correctIndex: 2, answer: "TSH is the most sensitive screening test because the pituitary responds to even minor changes in thyroid hormone levels with significant TSH changes. Elevated TSH indicates hypothyroidism; suppressed TSH indicates hyperthyroidism. Free T4 is ordered only if TSH is abnormal.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-2", type: "question", question: "In thyroid storm, why should aspirin be AVOIDED for fever?", options: ["Aspirin is too weak for high fevers", "Aspirin displaces T4 from thyroid-binding globulin, increasing free (active) T4 and worsening thyrotoxicosis", "Aspirin causes hypothyroidism", "Aspirin interacts with antithyroid drugs"], correctIndex: 1, answer: "Aspirin increases free T4 levels by displacing it from thyroid-binding proteins. Use acetaminophen instead for fever management in thyroid storm. External cooling measures (cooling blankets, ice packs) are also used.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-3", type: "question", question: "A patient on methimazole reports sore throat and fever. What should the nurse instruct?", options: ["Take OTC cold medication", "Come to the ED immediately for CBC — these are warning signs of agranulocytosis", "Continue medication and rest", "Switch to ibuprofen for fever"], correctIndex: 1, answer: "Sore throat and fever in a patient on thionamide antithyroid drugs (methimazole, PTU) are red flags for agranulocytosis — a potentially fatal drop in neutrophils. An immediate CBC with differential is required. If ANC is critically low, the medication must be stopped.", category: "Endocrine", difficulty: 2, clinicalPearl: "Agranulocytosis from methimazole occurs in 0.2-0.5% of patients, usually within the first 3 months. It is more common in older patients and with higher doses." },
  { id: "rn-patho-thyroid-4", type: "question", question: "The correct sequence for administering medications in thyroid storm is:", options: ["Iodide → antithyroid drugs → beta-blockers", "Antithyroid drugs FIRST → beta-blockers → iodide given 1 HOUR after antithyroid drugs", "Beta-blockers only", "Aspirin → antithyroid drugs → iodide"], correctIndex: 1, answer: "Antithyroid drugs (PTU preferred in storm because it also blocks T4→T3 conversion) must be given FIRST to block new hormone synthesis. Then beta-blockers for symptom control. Iodide is given 1 HOUR AFTER antithyroid drugs — if given first, iodide provides substrate for new hormone synthesis.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-5", type: "question", question: "Hashimoto thyroiditis is characterized by:", options: ["TSI antibodies causing hyperthyroidism", "Anti-TPO antibodies causing autoimmune thyroid destruction leading to hypothyroidism", "Iodine excess causing thyroid enlargement", "Thyroid cancer"], correctIndex: 1, answer: "Hashimoto thyroiditis is an organ-specific autoimmune disease where anti-TPO antibodies (present in >90%) and cytotoxic T cells progressively destroy thyroid follicular cells, leading to hypothyroidism. It is the most common cause of hypothyroidism in iodine-sufficient regions.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-6", type: "question", question: "Graves ophthalmopathy causes proptosis (bulging eyes) because:", options: ["High thyroid hormone levels directly enlarge the eyes", "TSI antibodies activate TSH receptors on orbital fibroblasts, causing retro-orbital inflammation, fat expansion, and muscle swelling", "Iodine deposits behind the eyes", "Fluid overload from hyperthyroidism"], correctIndex: 1, answer: "Orbital fibroblasts and adipocytes express TSH receptors. TSI antibodies in Graves disease activate these receptors, triggering inflammation, glycosaminoglycan deposition, adipogenesis, and extraocular muscle swelling within the rigid bony orbit, pushing the eyeball forward.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-7", type: "question", question: "A patient on levothyroxine should be taught to separate it from calcium and iron supplements by:", options: ["No separation needed", "At least 4 hours", "30 minutes", "1 hour"], correctIndex: 1, answer: "Calcium, iron, and aluminum-containing antacids bind levothyroxine in the GI tract, dramatically reducing its absorption. A minimum 4-hour separation is recommended. Levothyroxine should be taken first thing in the morning on an empty stomach.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-8", type: "question", question: "Which medication is preferred for hyperthyroidism during the FIRST trimester of pregnancy?", options: ["Methimazole", "Propylthiouracil (PTU) — methimazole is teratogenic in the first trimester", "Radioactive iodine", "Propranolol alone"], correctIndex: 1, answer: "PTU is preferred in the first trimester because methimazole crosses the placenta more readily and is associated with aplasia cutis (scalp defects) and choanal atresia. After the first trimester, methimazole is preferred due to PTU's higher risk of hepatotoxicity. RAI is absolutely contraindicated in pregnancy.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-9", type: "question", question: "Myxedema coma is characterized by:", options: ["Hyperthermia, tachycardia, and agitation", "Hypothermia, profound bradycardia, hypoventilation, and altered consciousness — a life-threatening hypothyroid emergency", "Normal vital signs with skin changes only", "Hyperglycemia and polyuria"], correctIndex: 1, answer: "Myxedema coma is the extreme manifestation of hypothyroidism with hypothermia (<95°F), bradycardia, hypoventilation (CO2 retention), altered mental status progressing to coma, and non-pitting edema. Mortality is 30-60% even with treatment. Requires IV levothyroxine and supportive ICU care.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-10", type: "question", question: "After thyroidectomy, the nurse should monitor for hypocalcemia because:", options: ["The thyroid produces calcium", "The parathyroid glands may be inadvertently damaged or removed, reducing PTH and calcium levels", "Blood loss causes calcium depletion", "Anesthesia lowers calcium"], correctIndex: 1, answer: "The four parathyroid glands are embedded in the posterior thyroid capsule. During thyroidectomy, they may be inadvertently damaged, devascularized, or removed, causing hypoparathyroidism and acute hypocalcemia. Monitor for Chvostek sign, Trousseau sign, perioral/fingertip tingling.", category: "Endocrine", difficulty: 1, clinicalPearl: "Post-thyroidectomy bedside: calcium gluconate IV and tracheostomy set must be at bedside. Check for Chvostek (facial twitch with cheek tap) and Trousseau (carpopedal spasm with BP cuff inflation) every 2-4 hours." },
  { id: "rn-patho-thyroid-11", type: "question", question: "Radioactive iodine (RAI) ablation for Graves disease works by:", options: ["Surgically removing the thyroid", "Delivering targeted radiation to thyroid follicular cells that concentrate iodine, destroying them over weeks", "Blocking thyroid hormone receptors", "Suppressing TSH production"], correctIndex: 1, answer: "The thyroid gland actively concentrates iodine via the sodium-iodide symporter (NIS). Radioactive I-131 is taken up by thyroid cells, where its beta radiation destroys the follicular cells locally over 6-18 weeks. Most patients eventually become hypothyroid and require lifelong levothyroxine.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-12", type: "question", question: "Morning stiffness lasting >1 hour is associated with:", options: ["Osteoarthritis", "Inflammatory conditions including Hashimoto thyroiditis (associated autoimmune conditions) and rheumatoid arthritis", "Normal aging", "Vitamin D deficiency"], correctIndex: 1, answer: "Prolonged morning stiffness (>1 hour) is a hallmark of inflammatory conditions. Hashimoto thyroiditis frequently coexists with other autoimmune diseases (RA, T1DM, celiac, vitiligo) — the autoimmune polyendocrine syndromes.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-13", type: "question", question: "Propranolol is used in hyperthyroidism for which unique dual mechanism?", options: ["It lowers thyroid hormone production", "It blocks beta-adrenergic symptoms AND inhibits peripheral T4-to-T3 conversion", "It reduces iodine uptake", "It enhances methimazole absorption"], correctIndex: 1, answer: "Propranolol provides symptomatic relief (blocks tachycardia, tremor, anxiety via beta-blockade) AND has a unique pharmacological property: it inhibits type 1 deiodinase, blocking peripheral conversion of inactive T4 to active T3. No other beta-blocker has this dual mechanism.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-14", type: "question", question: "The Burch-Wartofsky Point Scale is used to:", options: ["Diagnose hypothyroidism", "Clinically score the likelihood of thyroid storm based on temperature, CNS effects, GI symptoms, HR, HF, and precipitant", "Measure thyroid nodule size", "Predict thyroid cancer risk"], correctIndex: 1, answer: "The BWPS is a clinical scoring system that quantifies the likelihood of thyroid storm by assigning points for temperature elevation, CNS effects (agitation to coma), GI/hepatic dysfunction, heart rate, heart failure, and atrial fibrillation. Score ≥45 = highly suggestive of thyroid storm.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-15", type: "question", question: "Pretibial myxedema is associated with:", options: ["Hypothyroidism", "Graves disease specifically — localized dermopathy on the anterior shins from glycosaminoglycan deposition", "Hashimoto thyroiditis", "All thyroid disorders"], correctIndex: 1, answer: "Pretibial myxedema is specific to Graves disease — it presents as localized, non-pitting, raised, waxy, orange-peel textured skin on the anterior shins. It results from glycosaminoglycan (hyaluronan) deposition by fibroblasts activated by TSI antibodies binding to TSH receptors in the skin.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-16", type: "question", question: "A patient's TSH is elevated and free T4 is low. This indicates:", options: ["Hyperthyroidism", "Primary hypothyroidism (the thyroid is failing, so the pituitary increases TSH to compensate)", "Normal thyroid function", "Pituitary tumor"], correctIndex: 1, answer: "Elevated TSH + low free T4 = primary hypothyroidism. The thyroid gland is not producing enough hormone, so the pituitary responds by increasing TSH production in an attempt to stimulate the failing thyroid. This is the most common thyroid test pattern in clinical practice.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-17", type: "question", question: "Levothyroxine dose adjustments should be monitored by rechecking TSH after:", options: ["1 week", "4-6 weeks (the time required for a new steady state to be reached)", "24 hours", "6 months"], correctIndex: 1, answer: "Levothyroxine has a long half-life (approximately 7 days), so it takes 4-6 weeks to reach a new steady state after any dose change. Checking TSH earlier would not reflect the true effect of the dose adjustment and could lead to inappropriate over- or under-dosing.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-18", type: "question", question: "Amiodarone can cause thyroid dysfunction because:", options: ["It is structurally similar to thyroxine", "It contains 37% iodine by weight, which can trigger both hypothyroidism (Wolff-Chaikoff effect) and hyperthyroidism (Jod-Basedow effect)", "It destroys the pituitary gland", "It blocks iodine absorption"], correctIndex: 1, answer: "Amiodarone contains approximately 37% iodine by weight, providing a massive iodine load with each dose. This can cause: hypothyroidism (via the Wolff-Chaikoff effect — iodine excess inhibiting organification) or hyperthyroidism (via the Jod-Basedow effect — excess iodine fueling autonomous hormone production).", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-19", type: "question", question: "Post-thyroidectomy, which emergency equipment must be at the bedside?", options: ["Defibrillator only", "Calcium gluconate IV AND a tracheostomy set", "Insulin and glucose", "Chest tube insertion kit"], correctIndex: 1, answer: "Two critical post-thyroidectomy emergencies require immediate bedside equipment: (1) Hypocalcemia from parathyroid damage — calcium gluconate IV for treatment; (2) Airway obstruction from hemorrhage/hematoma or bilateral recurrent laryngeal nerve injury — tracheostomy set for emergency airway.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-20", type: "question", question: "A post-thyroidectomy patient shows a positive Trousseau sign. This indicates:", options: ["Normal neurological function", "Hypocalcemia — carpopedal spasm induced by BP cuff inflation indicates serum calcium is dangerously low", "Hypercalcemia", "Stroke"], correctIndex: 1, answer: "Trousseau sign is carpopedal spasm (hand/wrist flexion) that occurs when a blood pressure cuff is inflated above systolic pressure for 3 minutes. It indicates latent tetany from hypocalcemia, which in post-thyroidectomy patients results from parathyroid gland damage.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-21", type: "question", question: "The Wolff-Chaikoff effect describes:", options: ["Iodine deficiency causing goiter", "A temporary decrease in thyroid hormone synthesis when exposed to high iodine loads — a protective mechanism exploited therapeutically", "Thyroid cancer from radiation", "Autoimmune thyroid destruction"], correctIndex: 1, answer: "The Wolff-Chaikoff effect is the thyroid's autoregulatory response to excess iodine: high iodine concentrations temporarily inhibit thyroid peroxidase (organification), reducing T3/T4 synthesis. This is exploited therapeutically in thyroid storm by giving iodide (SSKI/Lugol) to rapidly block hormone release.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-22", type: "question", question: "Which finding on thyroid palpation is most concerning for malignancy?", options: ["Smooth, diffuse goiter", "A firm, fixed, irregular, non-tender thyroid nodule", "Tender thyroid during a viral illness", "Symmetrically enlarged thyroid"], correctIndex: 1, answer: "A firm, fixed (immobile), irregular, non-tender thyroid nodule raises concern for thyroid cancer. Additional red flags include rapid growth, cervical lymphadenopathy, hoarseness (recurrent laryngeal nerve involvement), and history of head/neck radiation.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-23", type: "question", question: "Subclinical hypothyroidism is defined as:", options: ["Symptomatic hypothyroidism requiring treatment", "Elevated TSH with NORMAL free T4 levels — the earliest biochemical stage of thyroid failure", "Normal TSH with low T4", "Suppressed TSH with normal T4"], correctIndex: 1, answer: "Subclinical hypothyroidism represents early thyroid failure where the pituitary detects a subtle decline in thyroid hormone and compensates by increasing TSH. Free T4 remains normal due to the increased TSH drive. Treatment is considered when TSH >10 or if symptomatic.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-24", type: "question", question: "Thyroid hormone replacement in a patient with coexisting adrenal insufficiency requires:", options: ["Starting levothyroxine first", "Starting cortisol replacement FIRST — levothyroxine increases cortisol metabolism and can precipitate adrenal crisis if adrenal insufficiency is untreated", "Starting both simultaneously", "No special consideration"], correctIndex: 1, answer: "Thyroid hormone increases cortisol metabolism and clearance. If levothyroxine is started without adequate cortisol replacement in a patient with adrenal insufficiency, it can precipitate a life-threatening adrenal crisis. Always replace cortisol BEFORE thyroid hormone.", category: "Endocrine", difficulty: 3, clinicalPearl: "Sequence matters: cortisol → levothyroxine → insulin. This is a frequently tested concept." },
  { id: "rn-patho-thyroid-25", type: "question", question: "Radioactive iodine therapy is ABSOLUTELY contraindicated in:", options: ["Elderly patients", "Pregnancy and breastfeeding", "Male patients", "Patients with large goiters"], correctIndex: 1, answer: "RAI crosses the placenta and concentrates in the fetal thyroid gland, destroying it and causing congenital hypothyroidism and cretinism. It is also secreted in breast milk. Pregnancy must be ruled out before RAI, and women should wait 6-12 months after RAI before conceiving.", category: "Endocrine", difficulty: 1 },

  // ============================================================
  // ADRENAL DISORDERS & HPA AXIS (25 cards combined)
  // ============================================================
  { id: "rn-patho-adrenal-1", type: "question", question: "The hallmark sign that differentiates PRIMARY from SECONDARY adrenal insufficiency is:", options: ["Fatigue", "Hyperpigmentation (present in primary, absent in secondary)", "Hypotension", "Hyponatremia"], correctIndex: 1, answer: "Hyperpigmentation occurs ONLY in primary adrenal insufficiency because the destroyed adrenal cortex removes cortisol negative feedback, causing massive ACTH elevation. ACTH's precursor POMC also produces MSH, which stimulates melanocytes. In secondary (pituitary), ACTH is LOW, so no hyperpigmentation.", category: "Endocrine", difficulty: 2, clinicalPearl: "Look for hyperpigmentation in skin creases, buccal mucosa, and sun-exposed areas. Its absence in a patient with adrenal insufficiency suggests a PITUITARY (secondary) cause." },
  { id: "rn-patho-adrenal-2", type: "question", question: "In adrenal crisis, what is the FIRST medication to administer?", options: ["Fludrocortisone orally", "IV hydrocortisone 100mg STAT", "Oral prednisone", "IV antibiotics"], correctIndex: 1, answer: "Adrenal crisis is immediately life-threatening. IV hydrocortisone 100mg STAT is the first-line treatment — do NOT delay for diagnostic testing. Follow with aggressive IV normal saline bolus. At high doses, hydrocortisone provides both glucocorticoid AND mineralocorticoid coverage.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-3", type: "question", question: "Cushing syndrome causes purple striae on the abdomen because:", options: ["Allergic skin reaction", "Cortisol inhibits collagen synthesis, weakening the skin; rapid fat deposition stretches the weakened skin, exposing underlying blood vessels", "Infection of the skin", "Mechanical injury from tight clothing"], correctIndex: 1, answer: "Chronic cortisol excess inhibits fibroblast collagen synthesis, making the skin thin and fragile. Cortisol simultaneously promotes central fat deposition. The combination of weakened skin stretched over rapidly expanding fat deposits creates wide, purple (violaceous) striae.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-4", type: "question", question: "Stress dosing for a patient with adrenal insufficiency undergoing minor dental procedure:", options: ["No medication changes needed", "Double the usual hydrocortisone dose on the day of the procedure", "Give IV hydrocortisone 100mg", "Stop hydrocortisone for the procedure"], correctIndex: 1, answer: "Minor stress (dental procedure, mild illness): double the usual daily dose. Moderate stress (moderate illness, minor surgery): triple the dose or 50mg q8h. Major stress (septic shock, major surgery): 100mg IV q8h. Always taper back to maintenance as stress resolves.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-5", type: "question", question: "Which electrolyte pattern is characteristic of primary adrenal insufficiency?", options: ["Hypernatremia and hypokalemia", "Hyponatremia and hyperkalemia (from aldosterone deficiency)", "Normal electrolytes", "Hypercalcemia and hypophosphatemia"], correctIndex: 1, answer: "Loss of aldosterone in primary adrenal insufficiency impairs sodium reabsorption and potassium excretion in the distal nephron. This causes hyponatremia (sodium wasting), hyperkalemia (potassium retention), and hypovolemia (water follows sodium).", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-6", type: "question", question: "The gold standard test for diagnosing adrenal insufficiency is:", options: ["Morning cortisol level alone", "ACTH stimulation test (cosyntropin test)", "Random cortisol level", "Urinary cortisol"], correctIndex: 1, answer: "The ACTH (cosyntropin) stimulation test is the gold standard. After IV administration of 250mcg synthetic ACTH (cosyntropin), a normal adrenal gland responds with cortisol rising to >18-20 mcg/dL within 30-60 minutes. Failure to respond confirms adrenal insufficiency.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-7", type: "question", question: "Fludrocortisone is prescribed only for PRIMARY adrenal insufficiency because:", options: ["Secondary insufficiency does not cause fatigue", "In primary AI, both cortisol AND aldosterone are lost; in secondary, aldosterone is preserved because it is regulated by RAAS, not ACTH", "Fludrocortisone is not available for secondary AI", "There is no difference between primary and secondary"], correctIndex: 1, answer: "Aldosterone secretion is primarily regulated by the renin-angiotensin-aldosterone system (RAAS) and potassium levels, NOT by ACTH. Therefore, in secondary adrenal insufficiency (pituitary ACTH deficiency), aldosterone production remains intact, and mineralocorticoid replacement is not needed.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-adrenal-8", type: "question", question: "The most important teaching point for patients with adrenal insufficiency:", options: ["Avoid all physical activity", "NEVER stop corticosteroids abruptly, always wear medical alert identification, carry an emergency injection kit, and know stress dosing rules", "Take the medication only when feeling unwell", "No dietary restrictions needed"], correctIndex: 1, answer: "These are the four pillars of adrenal insufficiency education: (1) Never stop steroids abruptly; (2) Wear medical alert ID at all times; (3) Carry an emergency IM hydrocortisone kit; (4) Know stress dosing rules (double for minor illness, triple for major stress).", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-9", type: "question", question: "How long can HPA axis suppression persist after stopping chronic corticosteroid therapy?", options: ["24 hours", "1 week", "Up to 12 months", "It recovers immediately"], correctIndex: 2, answer: "Chronic exogenous corticosteroids cause adrenal atrophy from prolonged HPA axis suppression. After discontinuation, the adrenal glands may take up to 12 months (sometimes longer) to fully recover function. Patients remain at risk for adrenal crisis during this recovery period.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-10", type: "question", question: "Cushing syndrome patients are at increased risk for which infections?", options: ["Only viral infections", "Opportunistic infections including Pneumocystis jirovecii pneumonia and candidiasis, due to cortisol-mediated immunosuppression", "No increased infection risk", "Only skin infections"], correctIndex: 1, answer: "Cortisol suppresses virtually all aspects of the immune response: T-cell function, neutrophil migration, cytokine production, and antibody synthesis. This creates susceptibility to opportunistic infections (PJP, candidiasis, herpes reactivation) and impairs wound healing.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-11", type: "question", question: "A Cushing syndrome patient's overnight dexamethasone suppression test shows failure to suppress morning cortisol below 1.8 mcg/dL. This means:", options: ["Normal result", "Abnormal — suggests autonomous cortisol production that is not regulated by normal HPA feedback", "The test was performed incorrectly", "The patient has adrenal insufficiency"], correctIndex: 1, answer: "In the 1mg overnight DST, dexamethasone should suppress CRH/ACTH and lower morning cortisol to <1.8 mcg/dL. Failure to suppress indicates cortisol production is autonomous (not under normal HPA axis negative feedback control), supporting Cushing syndrome.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-adrenal-12", type: "question", question: "Waterhouse-Friderichsen syndrome is:", options: ["Chronic adrenal insufficiency", "Bilateral adrenal hemorrhage and acute adrenal crisis caused by meningococcal septicemia", "A thyroid disorder", "A pituitary tumor syndrome"], correctIndex: 1, answer: "Waterhouse-Friderichsen syndrome is fulminant meningococcemia causing DIC, bilateral adrenal hemorrhagic infarction, and acute adrenal crisis. It presents with purpura fulminans, shock, and rapid cardiovascular collapse. Requires immediate IV hydrocortisone and antibiotics.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-adrenal-13", type: "question", question: "Cortisol follows a circadian rhythm. When is cortisol normally highest?", options: ["Midnight", "Early morning (6-8 AM — the cortisol awakening response)", "Mid-afternoon", "Late evening"], correctIndex: 1, answer: "Cortisol follows a robust circadian rhythm driven by the suprachiasmatic nucleus, peaking at 6-8 AM to prepare the body for the metabolic demands of waking (the cortisol awakening response) and reaching its nadir at midnight. This pattern is disrupted in Cushing syndrome.", category: "Endocrine", difficulty: 1 },

  // ============================================================
  // LEUKEMIA (25 cards)
  // ============================================================
  { id: "rn-patho-leuk-1", type: "question", question: "Auer rods on a peripheral blood smear are pathognomonic for:", options: ["ALL", "AML (Auer rods are NEVER found in ALL)", "Iron deficiency anemia", "Normal blood cells"], correctIndex: 1, answer: "Auer rods are needle-shaped cytoplasmic inclusions of fused azurophilic granules containing crystallized myeloperoxidase, found exclusively in myeloblasts. They confirm AML and are never seen in ALL. 'Faggot cells' (multiple Auer rods) indicate APL.", category: "Hematology", difficulty: 2, clinicalPearl: "Auer rods = AML. No Auer rods can be either ALL or AML. The presence of Auer rods immediately rules out ALL." },
  { id: "rn-patho-leuk-2", type: "question", question: "The leading cause of death in leukemia patients is:", options: ["Hemorrhage", "Infection (due to neutropenia from bone marrow failure and immunosuppressive therapy)", "Organ failure", "Medication toxicity"], correctIndex: 1, answer: "Infection is the leading cause of death in leukemia patients. Bone marrow failure produces severe neutropenia (ANC <500), and chemotherapy further suppresses the immune system. Febrile neutropenia requires immediate blood cultures and empiric broad-spectrum antibiotics within 1 hour.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-leuk-3", type: "question", question: "Tumor lysis syndrome is characterized by which electrolyte pattern?", options: ["Low potassium, low phosphorus, high calcium", "High potassium, high phosphorus, LOW calcium, high uric acid", "Normal electrolytes with elevated glucose", "Low sodium and low chloride"], correctIndex: 1, answer: "TLS occurs when massive cancer cell lysis releases intracellular contents: potassium (hyperkalemia → arrhythmias), phosphorus (hyperphosphatemia → binds calcium → hypocalcemia → tetany/seizures), nucleic acids (hyperuricemia → renal tubular obstruction → AKI).", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-4", type: "question", question: "ALL is the most common childhood malignancy. What is the peak age of incidence?", options: ["Newborns", "2-5 years of age", "10-15 years of age", "Over 60 years"], correctIndex: 1, answer: "ALL has a bimodal age distribution with a peak at ages 2-5 in children (the most common childhood malignancy) and a second peak in elderly adults. The childhood form has an excellent prognosis with approximately 90% cure rates with modern multi-agent chemotherapy protocols.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-leuk-5", type: "question", question: "The Philadelphia chromosome t(9;22) in ALL:", options: ["Confers excellent prognosis", "Confers poor prognosis — the BCR-ABL1 fusion protein is a constitutively active tyrosine kinase driving uncontrolled blast proliferation", "Has no prognostic significance", "Is only found in CML"], correctIndex: 1, answer: "The Philadelphia chromosome creates the BCR-ABL1 fusion protein, a constitutively active tyrosine kinase. In ALL, it occurs in 25% of adults and confers poor prognosis. Targeted therapy with tyrosine kinase inhibitors (imatinib/dasatinib) is added to chemotherapy.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-6", type: "question", question: "Why are blood products for leukemia patients irradiated?", options: ["To warm the blood", "To prevent transfusion-associated graft-versus-host disease by inactivating donor lymphocytes in severely immunocompromised patients", "To kill bacteria", "Irradiation is not necessary"], correctIndex: 1, answer: "Irradiation inactivates donor T lymphocytes in blood products, preventing them from engrafting in the severely immunocompromised leukemia patient and attacking host tissues (TA-GVHD). TA-GVHD is nearly always fatal, making irradiation essential.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-7", type: "question", question: "ATRA (all-trans retinoic acid) is the cornerstone treatment for:", options: ["ALL", "Acute promyelocytic leukemia (APL/AML-M3) — it induces differentiation of malignant promyelocytes", "CML", "CLL"], correctIndex: 1, answer: "ATRA is a unique 'differentiation therapy' that binds the PML-RARA fusion protein in APL cells, releasing the block on differentiation and forcing malignant promyelocytes to mature into functional neutrophils. Combined with arsenic trioxide, it has transformed APL cure rates to >90%.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-8", type: "question", question: "Differentiation syndrome during ATRA therapy presents as:", options: ["Hypoglycemia and bradycardia", "Fever, dyspnea, pulmonary infiltrates, weight gain, and pleural/pericardial effusions — can be fatal without immediate dexamethasone", "Skin rash only", "Diarrhea and vomiting"], correctIndex: 1, answer: "As promyelocytes differentiate into neutrophils under ATRA, massive cytokine release causes capillary leak syndrome with fever, respiratory distress, weight gain, and effusions. Treatment is immediate IV dexamethasone 10mg q12h. Occurs in 10-25% of APL patients.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-9", type: "question", question: "Leukostasis is a medical emergency occurring when:", options: ["Hemoglobin is very low", "WBC exceeds 100,000/uL, causing sludging of blast cells in pulmonary and cerebral microvasculature (respiratory failure, stroke)", "Platelets are very low", "INR is elevated"], correctIndex: 1, answer: "Leukostasis occurs with extreme leukocytosis (WBC >100,000). Blast cells are larger and stickier than mature cells, causing sludging in the microvasculature. Pulmonary leukostasis causes respiratory failure; cerebral leukostasis causes headache, confusion, and stroke. Emergent leukapheresis is required.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-10", type: "question", question: "The AML '7+3' induction regimen refers to:", options: ["7 days of rest + 3 days of chemotherapy", "7 days of continuous cytarabine + 3 days of daunorubicin", "7 doses of oral medication + 3 days of IV therapy", "7 weeks of treatment + 3 weeks of recovery"], correctIndex: 1, answer: "The '7+3' regimen is the standard induction chemotherapy for AML: 7 consecutive days of continuous IV cytarabine infusion plus 3 days of IV daunorubicin (an anthracycline). This produces severe aplasia lasting 3-4 weeks, requiring hospitalization for supportive care.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-11", type: "question", question: "Vincristine must NEVER be given by which route?", options: ["Intravenous", "Intramuscular", "Intrathecally — IT administration causes ascending paralysis and death", "Subcutaneous"], correctIndex: 2, answer: "Intrathecal vincristine is uniformly fatal, causing ascending motor and sensory neuropathy, paralysis, and death. It must be administered ONLY by IV push. Many institutions have safety protocols requiring that vincristine be given at a different time and location from intrathecal medications.", category: "Hematology", difficulty: 2, clinicalPearl: "Remember: Vincristine = IV ONLY. Methotrexate can be given intrathecally. Never confuse the two." },
  { id: "rn-patho-leuk-12", type: "question", question: "DIC in acute promyelocytic leukemia occurs because:", options: ["Chemotherapy toxicity", "Malignant promyelocytes release tissue factor and cancer procoagulant, triggering systemic coagulation cascade activation", "Liver failure", "Vitamin K deficiency"], correctIndex: 1, answer: "APL cells are heavily granulated and release tissue factor (activating extrinsic coagulation pathway) and cancer procoagulant (directly activating factor X). Additionally, annexin II on APL cells enhances plasmin generation, causing hyperfibrinolysis. The result is simultaneous clotting and bleeding.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-13", type: "question", question: "Rasburicase for TLS prophylaxis is contraindicated in patients with:", options: ["Diabetes", "G6PD deficiency (causes severe hemolytic anemia and methemoglobinemia)", "Hypertension", "Liver disease"], correctIndex: 1, answer: "Rasburicase converts uric acid to allantoin via urate oxidase reaction, generating hydrogen peroxide as a byproduct. In G6PD-deficient patients, who cannot generate adequate NADPH to neutralize oxidative stress, this causes severe hemolytic anemia and methemoglobinemia.", category: "Hematology", difficulty: 3 },

  // ============================================================
  // SICKLE CELL (12 cards)
  // ============================================================
  { id: "rn-patho-sickle-1", type: "question", question: "The MOST important initial intervention in sickle cell vaso-occlusive crisis is:", options: ["Apply cold compresses", "IV hydration (1.5x maintenance) to reduce HbS concentration and improve blood flow", "Genetic counseling", "Supplemental oxygen for all patients"], correctIndex: 1, answer: "IV hydration is the #1 priority. Dehydration concentrates HbS, promoting polymerization and sickling. Aggressive hydration (D5-1/2NS at 1.5x maintenance) dilutes HbS, improves blood flow, and reduces sickling. Oxygen is given only if SpO2 <92% or below baseline.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-sickle-2", type: "question", question: "Why should cold compresses be AVOIDED in sickle cell crisis?", options: ["Cold is uncomfortable", "Cold causes vasoconstriction, which slows blood flow and worsens vaso-occlusion and sickling", "Cold increases pain perception", "Cold has no effect on sickle cell"], correctIndex: 1, answer: "Cold causes vasoconstriction, slowing blood flow through small vessels. Slower flow increases the transit time of RBCs through capillaries, allowing more deoxygenation and HbS polymerization. This worsens the vaso-occlusive process. Use WARM compresses instead.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-sickle-3", type: "question", question: "Acute chest syndrome in sickle cell disease is defined as:", options: ["Any chest pain in a sickle cell patient", "A new pulmonary infiltrate on CXR with fever, chest pain, cough, and/or hypoxemia — the leading cause of death in SCD", "Pneumonia without any other findings", "Heart failure from anemia"], correctIndex: 1, answer: "ACS is defined by a NEW pulmonary infiltrate plus respiratory symptoms (fever, chest pain, cough, dyspnea, hypoxemia). It results from pulmonary vaso-occlusion, fat embolism from infarcted bone marrow, infection, or hypoventilation. It is the leading cause of death in SCD.", category: "Hematology", difficulty: 2, clinicalPearl: "Any sickle cell patient with new respiratory symptoms needs immediate chest X-ray, continuous pulse oximetry, blood cultures, and aggressive treatment including transfusion if indicated." },
  { id: "rn-patho-sickle-4", type: "question", question: "Hydroxyurea reduces sickle cell crisis frequency by:", options: ["Preventing dehydration", "Increasing fetal hemoglobin (HbF) production, which interrupts HbS polymerization", "Providing pain relief", "Replacing sickled red blood cells"], correctIndex: 1, answer: "Hydroxyurea stimulates HbF (fetal hemoglobin) production. HbF cannot participate in HbS polymer formation because it lacks the valine substitution at position 6. Even 20% HbF significantly reduces sickling. Hydroxyurea reduces crisis frequency by approximately 50%.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-5", type: "question", question: "Splenic sequestration crisis is most common in children under age 5 because:", options: ["Their spleens are larger", "Children under 5 still have functional spleens — by age 5-6, repeated infarction causes autosplenectomy in most SCD patients", "Children are more active", "Medication compliance is lower in children"], correctIndex: 1, answer: "In SCD, repeated sickling episodes cause splenic infarction, progressively destroying splenic tissue. By age 5-6, most SCD patients have functional asplenia (autosplenectomy). Before this occurs, the spleen can trap massive volumes of blood (splenic sequestration), causing acute severe anemia and hypovolemic shock.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-6", type: "question", question: "Aplastic crisis in SCD is most commonly caused by:", options: ["Iron deficiency", "Parvovirus B19 infection, which selectively infects and destroys erythroid precursors in the bone marrow", "Folate deficiency", "Chemotherapy"], correctIndex: 1, answer: "Parvovirus B19 has tropism for erythroid precursor cells expressing the P antigen. Infection temporarily halts red blood cell production (reticulocyte count drops to near zero). In SCD, where RBC lifespan is already shortened to 10-20 days, this causes rapid, severe anemia.", category: "Hematology", difficulty: 2 },

  // ============================================================
  // THALASSEMIA (6 cards)
  // ============================================================
  { id: "rn-patho-thal-1", type: "question", question: "How does thalassemia anemia differ from iron deficiency anemia on lab work?", options: ["They are identical", "Both cause microcytic anemia, but in thalassemia ferritin is NORMAL or HIGH, while in iron deficiency ferritin is LOW", "Thalassemia causes macrocytic anemia", "Iron deficiency has normal ferritin"], correctIndex: 1, answer: "This is a critical clinical distinction. Both produce microcytic hypochromic anemia (low MCV). However, iron studies differentiate: thalassemia has normal/elevated ferritin (often from transfusions or increased GI absorption) while iron deficiency has LOW ferritin. NEVER give iron to a thalassemia patient.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-2", type: "question", question: "Reddish-orange urine during deferoxamine therapy indicates:", options: ["Renal damage", "Expected finding — ferrioxamine (chelated iron) excretion in the urine", "Hematuria requiring immediate evaluation", "Medication allergy"], correctIndex: 1, answer: "Reddish-orange urine during deferoxamine therapy is NORMAL and EXPECTED. It indicates that the chelator is successfully binding iron (forming ferrioxamine complex) and excreting it through the kidneys. Patients should be informed about this expected color change.", category: "Hematology", difficulty: 1, clinicalPearl: "Reassure patients that this color change means the medication is working. If the urine does NOT change color, chelation may be inadequate." },
  { id: "rn-patho-thal-3", type: "question", question: "'Chipmunk facies' in thalassemia major is caused by:", options: ["Allergic reaction to transfusions", "Massive bone marrow expansion into facial bones, causing frontal bossing and prominent cheekbones", "Iron deposition in facial skin", "Steroid side effects"], correctIndex: 1, answer: "Severe anemia triggers erythropoietin-driven marrow expansion. The marrow space expands into cortical bone, particularly affecting the skull and facial bones, causing frontal bossing, prominent cheekbones (maxillary hyperplasia), flat nasal bridge, and 'hair-on-end' appearance on skull X-ray.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-4", type: "question", question: "The leading cause of death in thalassemia major is:", options: ["Infection", "Iron cardiomyopathy from cardiac iron deposition causing heart failure and fatal arrhythmias", "Bone fractures", "Liver failure"], correctIndex: 1, answer: "Iron-mediated cardiac damage is the leading cause of death in thalassemia major. Iron deposited in cardiac myocytes generates ROS via the Fenton reaction, causing oxidative damage leading to dilated cardiomyopathy and arrhythmias. Cardiac MRI T2* <10ms indicates high risk of cardiac events.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-5", type: "question", question: "Hepcidin suppression in thalassemia leads to:", options: ["Decreased iron absorption", "Increased intestinal iron absorption (3-5x normal), contributing to iron overload even WITHOUT transfusions", "Increased erythropoietin", "Decreased transferrin"], correctIndex: 1, answer: "Ineffective erythropoiesis in thalassemia produces erythroferrone, which suppresses hepcidin — the liver hormone that normally limits iron absorption. With hepcidin suppressed, ferroportin remains active, causing excessive intestinal iron absorption that contributes to iron overload.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-thal-6", type: "question", question: "The only curative treatment for thalassemia major is:", options: ["Iron chelation therapy", "Chronic blood transfusions", "Hematopoietic stem cell transplant (with gene therapy as an emerging option)", "Splenectomy"], correctIndex: 2, answer: "Allogeneic hematopoietic stem cell transplant is the only established curative treatment, providing a new source of normal hematopoietic stem cells that produce functional hemoglobin. Best outcomes are with HLA-matched sibling donors in young patients. Gene therapy (betibeglogene autotemcel) is an emerging curative approach.", category: "Hematology", difficulty: 1 },

  // ============================================================
  // PANCYTOPENIA (6 cards)
  // ============================================================
  { id: "rn-patho-pancy-1", type: "question", question: "Pancytopenia refers to the simultaneous decrease of:", options: ["Only red blood cells", "All three cell lines: red blood cells (anemia), white blood cells (leukopenia), and platelets (thrombocytopenia)", "Only white blood cells and platelets", "Red blood cells and hemoglobin only"], correctIndex: 1, answer: "Pancytopenia = pan (all) + cytopenia (cell deficiency). It means reduction in all three formed elements: RBCs (causing anemia), WBCs (causing leukopenia/neutropenia), and platelets (causing thrombocytopenia). It is a finding, not a diagnosis — always investigate the cause.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-pancy-2", type: "question", question: "In aplastic anemia, the bone marrow biopsy shows:", options: ["Hypercellular marrow with dysplastic changes", "Hypocellular marrow with fat replacement (the stem cells are destroyed)", "Normal marrow cellularity", "Blast cells filling the marrow"], correctIndex: 1, answer: "Aplastic anemia is characterized by a HYPOCELLULAR marrow (<25% cellularity) where normal hematopoietic tissue is replaced by fat. This contrasts with MDS (normocellular or hypercellular with dysplastic changes) and leukemia (hypercellular with blast infiltration).", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-3", type: "question", question: "MDS (myelodysplastic syndrome) differs from aplastic anemia in that:", options: ["MDS has a hypocellular marrow", "MDS shows a normocellular/hypercellular marrow with DYSPLASTIC cells and risk of transformation to AML (30%)", "They are the same condition", "MDS never causes pancytopenia"], correctIndex: 1, answer: "In MDS, the marrow is typically normocellular or hypercellular (full of cells), but the cells are dysplastic — morphologically abnormal with impaired maturation. They die prematurely within the marrow (ineffective hematopoiesis). Unlike aplastic anemia (empty marrow), MDS has a 30% risk of AML transformation.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-4", type: "question", question: "Fanconi anemia should be suspected in a child with pancytopenia PLUS:", options: ["Normal physical exam", "Café-au-lait spots, short stature, absent or hypoplastic thumbs, and renal anomalies", "Obesity and acanthosis nigricans", "Joint hypermobility"], correctIndex: 1, answer: "Fanconi anemia is an autosomal recessive DNA repair defect presenting with pancytopenia PLUS characteristic physical anomalies: café-au-lait spots, short stature, microcephaly, thumb/radial abnormalities (absent, hypoplastic, or triphalangeal thumbs), renal malformations. Confirm with chromosomal breakage study.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-5", type: "question", question: "A pancytopenic patient with ANC of 200 develops fever. In addition to infection, the nurse should be concerned that:", options: ["The fever might be the ONLY sign of life-threatening infection because neutropenia eliminates normal inflammatory responses (no pus, no erythema, no swelling)", "Fever is always benign in neutropenic patients", "Only documented infections need treatment", "The patient should wait for culture results before treatment"], correctIndex: 0, answer: "In neutropenic patients, the immune system cannot mount a normal inflammatory response. There is no pus formation, no localized redness, no swelling — fever may be the ONLY sign of life-threatening sepsis. This is why febrile neutropenia requires immediate empiric antibiotics without waiting for cultures.", category: "Hematology", difficulty: 2, clinicalPearl: "In neutropenic patients, absence of inflammatory signs does NOT mean absence of infection — it means the patient CANNOT mount an inflammatory response." },
  { id: "rn-patho-pancy-6", type: "question", question: "IM injections should be avoided in patients with pancytopenia because:", options: ["They are too painful", "Thrombocytopenia increases the risk of uncontrollable intramuscular hematoma, and neutropenia increases infection risk at the injection site", "Medications are not absorbed IM", "IM route is never used in hospital settings"], correctIndex: 1, answer: "Two simultaneous risks contraindicate IM injections: (1) Low platelets → risk of hematoma formation within muscle that cannot be compressed; (2) Low neutrophils → risk of localized infection at the injection site that cannot be effectively fought. Use subcutaneous or IV routes instead.", category: "Hematology", difficulty: 1 },

  // ============================================================
  // RHEUMATOID ARTHRITIS (12 cards)
  // ============================================================
  { id: "rn-patho-ra-1", type: "question", question: "The MOST critical medication safety point about methotrexate for RA is:", options: ["Take with food", "It is given ONCE WEEKLY — daily dosing can cause fatal bone marrow suppression and hepatotoxicity", "It can be stopped abruptly", "No lab monitoring is needed"], correctIndex: 1, answer: "Methotrexate for RA is dosed once WEEKLY (not daily). Daily dosing delivers a 7x overdose that causes fatal pancytopenia and hepatotoxicity. This is one of the most commonly tested medication safety points on nursing exams.", category: "Musculoskeletal", difficulty: 1, clinicalPearl: "Methotrexate = Monday only (or whichever one day per week is chosen). NEVER daily. Always supplement with folic acid 1mg daily." },
  { id: "rn-patho-ra-2", type: "question", question: "RA characteristically involves which joints?", options: ["DIP joints bilaterally", "MCP, PIP, and wrist joints SYMMETRICALLY (sparing DIP joints)", "Sacroiliac joints", "First MTP joint unilaterally"], correctIndex: 1, answer: "RA affects small joints of the hands symmetrically — MCP (knuckles), PIP (middle finger joints), and wrists. DIP joints are SPARED (DIP involvement = OA). First MTP = gout. Sacroiliac = ankylosing spondylitis. The symmetric pattern is a defining feature.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-ra-3", type: "question", question: "Before starting adalimumab (a TNF inhibitor) for RA, which screening test is ESSENTIAL?", options: ["Bone density scan", "PPD or IGRA for latent tuberculosis", "Echocardiogram", "Genetic testing"], correctIndex: 1, answer: "TNF-alpha is critical for granuloma formation and containment of Mycobacterium tuberculosis. TNF inhibitors dramatically increase the risk of reactivating latent TB. All patients must be screened with PPD or IGRA before initiation, and latent TB treated with isoniazid for 9 months first.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-4", type: "question", question: "Morning stiffness in RA typically lasts:", options: ["Less than 15 minutes", "Greater than 1 hour (and improves with activity)", "Exactly 30 minutes", "Morning stiffness does not occur in RA"], correctIndex: 1, answer: "RA morning stiffness typically lasts MORE than 1 hour and improves with activity as the joints warm up. This is a key differentiator from OA, where stiffness lasts LESS than 30 minutes. The duration of morning stiffness also serves as a marker of disease activity.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-ra-5", type: "question", question: "Anti-CCP antibodies in RA are important because:", options: ["They treat the disease", "They are highly specific (>95%) for RA and predict erosive disease progression", "They indicate infection", "They are found in all autoimmune diseases"], correctIndex: 1, answer: "Anti-CCP (anti-citrullinated protein) antibodies are >95% specific for RA (more specific than rheumatoid factor). Their presence predicts more aggressive, erosive disease and can be detected years before clinical symptoms appear, enabling earlier intervention.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-6", type: "question", question: "Swan-neck deformity in RA involves:", options: ["DIP hyperextension with PIP flexion", "PIP hyperextension with DIP flexion (the finger looks like a swan's neck)", "Ulnar deviation of the wrist", "Boutonnière deformity"], correctIndex: 1, answer: "Swan-neck deformity = PIP hyperextension + DIP flexion, caused by destruction of the volar plate at the PIP joint and shortening of the lateral bands. Boutonnière deformity is the opposite: PIP flexion + DIP hyperextension, caused by disruption of the central slip of the extensor tendon.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-7", type: "question", question: "TNF-alpha in RA pathology acts as:", options: ["A protective cytokine", "The master pro-inflammatory cytokine driving synovial inflammation, pannus formation, cartilage destruction, and bone erosion", "A pain receptor", "An anti-inflammatory mediator"], correctIndex: 1, answer: "TNF-alpha is the central cytokine in RA pathology: it stimulates synovial fibroblast proliferation (pannus), activates osteoclasts (bone erosion), induces MMP production (cartilage degradation), upregulates adhesion molecules (inflammatory cell recruitment), and amplifies other pro-inflammatory cytokines (IL-1, IL-6).", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-8", type: "question", question: "Labs to monitor regularly in a patient on methotrexate include:", options: ["Thyroid function tests", "CBC with differential and liver function tests (LFTs) every 4-8 weeks", "Glucose and HbA1c", "Urinalysis only"], correctIndex: 1, answer: "Methotrexate can cause bone marrow suppression (monitor CBC for pancytopenia) and hepatotoxicity (monitor LFTs for elevated transaminases). Check every 4-8 weeks. Also monitor renal function. Report leukopenia, thrombocytopenia, or LFT elevation immediately.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-ra-9", type: "question", question: "The pannus in RA is:", options: ["A type of medication", "Hyperplastic synovial tissue that invades and erodes cartilage and bone at the joint margins", "A skin rash", "A blood test result"], correctIndex: 1, answer: "The pannus is the hallmark destructive tissue of RA — a mass of hyperplastic synovium, inflammatory cells, fibroblasts, and granulation tissue. It invades the cartilage-bone junction (marginal zone), secreting MMPs that degrade cartilage and activating osteoclasts that erode subchondral bone.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-10", type: "question", question: "Cervical spine instability (atlantoaxial subluxation) in RA is a critical concern during:", options: ["Routine physical examination", "Intubation for general anesthesia — neck manipulation can cause spinal cord compression", "Blood draws", "Chest X-rays"], correctIndex: 1, answer: "RA-mediated destruction of the transverse ligament of the atlas allows C1-C2 subluxation. During intubation, neck extension can displace C1 on C2, compressing the spinal cord. Flexion/extension cervical X-rays should be obtained before elective surgery requiring general anesthesia in RA patients.", category: "Musculoskeletal", difficulty: 3 },
  { id: "rn-patho-ra-11", type: "question", question: "Smoking is the strongest MODIFIABLE risk factor for RA because:", options: ["Nicotine directly damages joints", "Smoking induces citrullination of proteins in the lungs, promoting formation of anti-CCP antibodies that drive RA pathology", "Smoking causes vitamin deficiency", "Smoking reduces immunity generally"], correctIndex: 1, answer: "Smoking activates the enzyme peptidylarginine deiminase (PAD) in the lungs, converting arginine to citrulline in proteins (citrullination). In genetically susceptible individuals (HLA-DR4), the immune system generates anti-citrullinated protein antibodies (anti-CCP), which initiate and perpetuate RA.", category: "Musculoskeletal", difficulty: 3 },
  { id: "rn-patho-ra-12", type: "question", question: "Folic acid is prescribed alongside methotrexate because:", options: ["It enhances methotrexate's effect", "It reduces methotrexate side effects (stomatitis, GI upset, hepatotoxicity) by replenishing folate depleted by methotrexate's antifolate mechanism", "It treats anemia", "It is a placebo"], correctIndex: 1, answer: "Methotrexate inhibits dihydrofolate reductase, depleting intracellular folate. Folic acid 1mg daily replenishes folate stores, reducing the incidence of stomatitis, nausea, hepatotoxicity, and bone marrow suppression WITHOUT reducing methotrexate's anti-inflammatory efficacy.", category: "Musculoskeletal", difficulty: 1 },

  // ============================================================
  // OSTEOARTHRITIS (6 cards)
  // ============================================================
  { id: "rn-patho-oa-1", type: "question", question: "The key clinical differentiator between OA and RA morning stiffness is:", options: ["No morning stiffness occurs in either", "OA stiffness lasts <30 minutes; RA stiffness lasts >1 hour", "Both have identical stiffness patterns", "OA stiffness is worse than RA"], correctIndex: 1, answer: "OA morning stiffness is brief (<30 minutes) and related to mechanical 'gelling' of the joint. RA stiffness is prolonged (>1 hour) and related to synovial inflammation that resolves with activity-induced warming. This is one of the most frequently tested clinical differentiators.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-2", type: "question", question: "Heberden nodes are found at:", options: ["MCP joints", "DIP joints (distal interphalangeal — pathognomonic for OA)", "PIP joints", "Wrist joints"], correctIndex: 1, answer: "Heberden nodes are bony enlargements at the DIP joints from osteophyte formation — they are pathognomonic for OA. Bouchard nodes occur at PIP joints. These bony changes help distinguish OA from RA, which affects MCP/PIP/wrists symmetrically and spares the DIP joints.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-3", type: "question", question: "A cane for right knee OA should be held in:", options: ["The right hand (same side)", "The LEFT hand (opposite side — to provide counterbalancing force)", "Either hand", "Both hands"], correctIndex: 1, answer: "The cane is held in the OPPOSITE hand and advanced WITH the affected leg. This creates a counterbalancing force that reduces load on the affected knee by up to 25%, mimicking the natural arm-leg opposition pattern of normal gait.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-4", type: "question", question: "Synovial fluid analysis in OA shows:", options: ["Cloudy, turbid fluid with high WBC count", "Clear, viscous fluid with WBC <2,000 (non-inflammatory pattern)", "Purulent fluid with bacteria", "Bloody fluid"], correctIndex: 1, answer: "OA is a primarily mechanical (non-inflammatory) process. Synovial fluid is clear, maintains high viscosity, and has a low WBC count (<2,000/uL). This contrasts sharply with RA (cloudy, decreased viscosity, WBC 5,000-50,000 with PMN predominance) and septic arthritis (purulent, WBC >50,000).", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-oa-5", type: "question", question: "Weight loss is particularly beneficial for knee OA because:", options: ["It improves self-esteem", "Every 1 pound of body weight lost removes approximately 4 pounds of mechanical force across the knee joint", "It has no effect on joints", "It reduces medication costs"], correctIndex: 1, answer: "The knee amplifies body weight forces: due to the biomechanics of walking, every 1 pound of body weight creates approximately 4 pounds of force across the knee joint. Therefore, even modest weight loss (5-10 pounds) provides significant mechanical relief, reducing pain and slowing cartilage degradation.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-6", type: "question", question: "OA is now understood to involve:", options: ["Only mechanical wear and tear", "Both mechanical cartilage degradation AND inflammatory components (cytokines, synovitis) that contribute to disease progression", "Only autoimmune inflammation", "Only bone remodeling"], correctIndex: 1, answer: "Modern understanding recognizes OA as more than simple 'wear and tear.' Cartilage degradation products activate innate immune receptors (TLR2/4) on synovial cells, triggering production of pro-inflammatory cytokines (IL-1, TNF-alpha) and secondary synovitis in up to 50% of patients.", category: "Musculoskeletal", difficulty: 2 },

  // ============================================================
  // OSTEOPOROSIS (12 cards)
  // ============================================================
  { id: "rn-patho-osteo-1", type: "question", question: "A DEXA scan T-score of -2.8 indicates:", options: ["Normal bone density", "Osteopenia", "Osteoporosis (T-score ≤ -2.5)", "Severe anemia"], correctIndex: 2, answer: "T-score ≤ -2.5 = osteoporosis. T-score -1.0 to -2.5 = osteopenia. T-score ≥ -1.0 = normal. A T-score of -2.8 meets the diagnostic threshold for osteoporosis and warrants pharmacological treatment plus calcium/vitamin D supplementation and fall prevention.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-osteo-2", type: "question", question: "Bisphosphonate administration requires the patient to:", options: ["Take with a large meal", "Take on empty stomach with FULL glass of PLAIN water, remain UPRIGHT 30 minutes, no food/drink/meds for 30 minutes", "Take with milk for calcium", "Take at bedtime lying down"], correctIndex: 1, answer: "These strict administration guidelines prevent esophageal irritation/erosion (the most common side effect) and maximize the very poor oral bioavailability (<1%). Food, calcium, minerals, and other medications all interfere with absorption.", category: "Musculoskeletal", difficulty: 1, clinicalPearl: "The mnemonic: First thing AM, Empty stomach, Full glass PLAIN water, stand/sit Upright 30 min, Nothing else for 30 min." },
  { id: "rn-patho-osteo-3", type: "question", question: "The RANK-RANKL-OPG pathway controls bone remodeling. Denosumab works by:", options: ["Stimulating osteoblasts", "Neutralizing RANKL (like a synthetic OPG), preventing osteoclast formation and bone resorption", "Providing calcium to bones", "Blocking estrogen receptors"], correctIndex: 1, answer: "Denosumab is a monoclonal antibody that binds and neutralizes RANKL, mimicking the natural action of OPG. By preventing RANKL from binding to RANK on osteoclast precursors, denosumab dramatically reduces osteoclast formation, activation, and survival.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-osteo-4", type: "question", question: "Why is denosumab discontinuation dangerous?", options: ["It causes allergic reactions", "Abrupt discontinuation causes severe REBOUND bone loss with rapid vertebral fractures — must transition to a bisphosphonate", "It has no discontinuation concerns", "It causes weight gain"], correctIndex: 1, answer: "When denosumab is stopped, RANKL is suddenly unopposed, causing a massive surge in osteoclast formation and bone resorption that exceeds pre-treatment rates. This 'rebound phenomenon' results in rapid bone loss and multiple spontaneous vertebral fractures within 12-18 months.", category: "Musculoskeletal", difficulty: 3, clinicalPearl: "Always plan a transition: give zoledronic acid IV approximately 6 months after the last denosumab injection to suppress the rebound resorption surge." },
  { id: "rn-patho-osteo-5", type: "question", question: "Estrogen protects against osteoporosis through which mechanism?", options: ["It provides calcium to bones", "It suppresses RANKL, increases OPG production, promotes osteoclast apoptosis, and stimulates osteoblast activity", "It strengthens muscles only", "It has no effect on bone"], correctIndex: 1, answer: "Estrogen is the most important hormonal regulator of bone metabolism in women. It suppresses RANKL (reducing osteoclast formation), increases OPG (further blocking RANKL), promotes osteoclast apoptosis (shortening their lifespan), and supports osteoblast survival. Menopause removes all these protections.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-osteo-6", type: "question", question: "Hip fractures in elderly osteoporotic patients carry a one-year mortality rate of:", options: ["<1%", "5-10%", "20-30%", "50%"], correctIndex: 2, answer: "Hip fractures in elderly patients carry a devastating 20-30% one-year mortality rate due to complications including DVT/PE, pneumonia, delirium, pressure injuries, and deconditioning. This underscores the critical importance of osteoporosis prevention and treatment.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-osteo-7", type: "question", question: "Progressive height loss of >1.5 inches from peak height suggests:", options: ["Normal aging", "Vertebral compression fractures from osteoporosis", "Dehydration", "Postural changes only"], correctIndex: 1, answer: "Height loss exceeding 1.5 inches (4 cm) from peak height strongly suggests vertebral compression fractures, which may be asymptomatic (only 1/3 are clinically recognized). Multiple anterior wedge fractures cause progressive thoracic kyphosis (dowager's hump).", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-osteo-8", type: "question", question: "Teriparatide (Forteo) is unique among osteoporosis drugs because:", options: ["It is a bisphosphonate", "It is an ANABOLIC agent that stimulates osteoblasts to BUILD new bone, rather than just slowing bone loss", "It provides calcium", "It blocks RANKL"], correctIndex: 1, answer: "Teriparatide is a recombinant PTH(1-34) analog. When given as daily intermittent subcutaneous injections, it preferentially stimulates osteoblasts over osteoclasts, BUILDING new bone (anabolic effect). This contrasts with antiresorptive agents (bisphosphonates, denosumab) that only slow bone loss.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-osteo-9", type: "question", question: "A patient on long-term prednisone therapy should be assessed for osteoporosis because:", options: ["Prednisone causes weight loss", "Glucocorticoids directly suppress osteoblast function, increase osteocyte apoptosis, and enhance RANKL expression, causing rapid bone loss", "Prednisone improves bone density", "There is no connection between prednisone and bones"], correctIndex: 1, answer: "Glucocorticoid-induced osteoporosis is the most common secondary cause of osteoporosis. Corticosteroids suppress osteoblasts, kill osteocytes, enhance RANKL/reduce OPG, decrease calcium absorption, and increase renal calcium excretion. Bone loss is most rapid in the first 6-12 months.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-osteo-10", type: "question", question: "The FRAX tool is used to:", options: ["Diagnose osteoporosis", "Calculate a patient's 10-year probability of major osteoporotic fracture and hip fracture, integrating BMD with clinical risk factors", "Measure bone turnover markers", "Determine medication dosages"], correctIndex: 1, answer: "FRAX integrates BMD (DEXA T-score) with clinical risk factors (age, sex, BMI, prior fracture, parental hip fracture, smoking, alcohol, corticosteroids, RA) to estimate 10-year fracture probability. Treatment is recommended when hip fracture risk ≥3% or major osteoporotic fracture risk ≥20%.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-osteo-11", type: "question", question: "Osteonecrosis of the jaw (ONJ) is a rare complication associated with:", options: ["Calcium supplements", "Long-term bisphosphonate or denosumab therapy (risk approximately 1 in 10,000-100,000)", "Vitamin D deficiency", "Exercise"], correctIndex: 1, answer: "ONJ is a rare but serious complication of antiresorptive therapy, presenting as exposed, non-healing bone in the jaw. Risk factors include dental procedures (tooth extraction), poor oral hygiene, and duration of therapy. Patients should complete dental work before starting therapy.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-osteo-12", type: "question", question: "Wolff's law states that bone:", options: ["Weakens with exercise", "Adapts its structure to the mechanical loads placed upon it — weight-bearing exercise stimulates bone formation", "Is not affected by exercise", "Only responds to calcium intake"], correctIndex: 1, answer: "Wolff's law explains why weight-bearing exercise strengthens bone. Mechanical loading stimulates osteocytes to signal osteoblast recruitment, increasing bone formation where stress is greatest. This is why weight-bearing exercises (walking, stair climbing, resistance training) are recommended for osteoporosis prevention.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-hpa-1", type: "question", question: "The hypothalamic-pituitary-adrenal (HPA) axis stress response begins with hypothalamic release of:", options: ["ACTH", "Cortisol", "Corticotropin-releasing hormone (CRH)", "Aldosterone"], correctIndex: 2, answer: "CRH released from the paraventricular nucleus of the hypothalamus stimulates anterior pituitary corticotrophs to release ACTH, which then stimulates adrenal cortical production of cortisol. This cascade is the central neuroendocrine stress response.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-2", type: "question", question: "Cortisol exerts negative feedback on the HPA axis by:", options: ["Stimulating more CRH release", "Inhibiting CRH release from the hypothalamus AND ACTH release from the anterior pituitary", "Increasing aldosterone production", "Activating the sympathetic nervous system"], correctIndex: 1, answer: "Cortisol binds to glucocorticoid receptors in both the hypothalamus and anterior pituitary, suppressing CRH and ACTH release respectively. This negative feedback loop normally prevents excessive cortisol production and restores homeostasis after a stress response.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-3", type: "question", question: "Chronic stress causes HPA axis dysregulation primarily through:", options: ["Increased aldosterone", "Sustained cortisol elevation that impairs negative feedback sensitivity, leading to a persistently activated stress response", "Decreased epinephrine", "Improved immune function"], correctIndex: 1, answer: "Chronic stress causes sustained cortisol elevation that downregulates glucocorticoid receptors, reducing the effectiveness of negative feedback. The HPA axis becomes persistently activated, leading to chronically elevated cortisol with wide-ranging metabolic, immune, and neurological consequences.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-4", type: "question", question: "Cortisol's primary metabolic effect during stress is:", options: ["Lowering blood glucose", "Mobilizing energy by increasing gluconeogenesis, promoting lipolysis, and enhancing protein catabolism", "Promoting glycogen storage", "Decreasing hepatic glucose output"], correctIndex: 1, answer: "Cortisol is a catabolic hormone that mobilizes energy stores: it increases hepatic gluconeogenesis (amino acids to glucose), promotes lipolysis (fatty acids for energy), and enhances muscle protein catabolism (amino acid substrates). This provides glucose for the brain and fatty acids for muscles during stress.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-5", type: "question", question: "The cortisol awakening response (CAR) refers to:", options: ["Cortisol decrease upon waking", "A natural 50-75% surge in cortisol within 30-45 minutes of awakening, reflecting HPA axis reactivity", "Cortisol levels that remain constant throughout the day", "Evening cortisol peak"], correctIndex: 1, answer: "The CAR is a natural physiologic phenomenon: cortisol surges 50-75% above baseline within 30-45 minutes of waking. It prepares the body for daily activities by mobilizing energy. An absent or exaggerated CAR is a biomarker of HPA axis dysregulation seen in chronic stress, depression, and PTSD.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-6", type: "question", question: "Chronic cortisol elevation suppresses the immune system by:", options: ["Increasing T-cell proliferation", "Promoting inflammatory cytokines", "Inhibiting NF-κB, suppressing pro-inflammatory cytokines, reducing lymphocyte proliferation, and promoting lymphocyte apoptosis", "Enhancing natural killer cell activity"], correctIndex: 2, answer: "Cortisol has powerful immunosuppressive effects: it inhibits the NF-κB transcription factor (reducing inflammatory gene expression), suppresses IL-1, IL-6, and TNF-α production, reduces T-cell and B-cell proliferation, and promotes lymphocyte apoptosis. This explains the increased infection risk in chronically stressed patients.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-7", type: "question", question: "Critical illness-related corticosteroid insufficiency (CIRCI) occurs when:", options: ["The adrenal glands produce too much cortisol", "The stress response produces insufficient cortisol relative to the severity of illness, OR peripheral tissues develop cortisol resistance", "ACTH levels are elevated", "The patient is on chronic steroids"], correctIndex: 1, answer: "CIRCI can result from inadequate cortisol production relative to the level of physiologic stress, or from tissue-level cortisol resistance. In sepsis, inflammatory cytokines can suppress adrenal cortisol synthesis and block glucocorticoid receptor signaling, causing functional cortisol insufficiency despite apparently normal or elevated levels.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-8", type: "question", question: "HPA axis suppression from exogenous corticosteroid use occurs when:", options: ["Steroids are used for less than 3 days", "Chronic exogenous cortisol suppresses CRH and ACTH via negative feedback, causing adrenal atrophy — abrupt discontinuation can cause adrenal crisis", "The patient takes steroids with food", "Only IV steroids cause suppression"], correctIndex: 1, answer: "Exogenous corticosteroids (prednisone, dexamethasone) provide supraphysiologic cortisol, chronically suppressing CRH and ACTH. Without ACTH stimulation, the adrenal cortex atrophies. Abrupt withdrawal removes exogenous cortisol while the atrophied adrenals cannot produce enough endogenous cortisol, causing adrenal crisis.", category: "Endocrine", difficulty: 2, clinicalPearl: "Taper protocols allow gradual HPA axis recovery. Risk increases with doses >7.5mg prednisone/day for >3 weeks." },
  { id: "rn-patho-hpa-9", type: "question", question: "The sympatho-adrenal-medullary (SAM) axis differs from the HPA axis in that it:", options: ["Is slower to activate", "Provides immediate fight-or-flight response via catecholamines (epinephrine/norepinephrine), while the HPA axis provides a slower, sustained cortisol response", "Only activates during sleep", "Has no role in acute stress"], correctIndex: 1, answer: "The SAM axis activates within seconds (via sympathetic nerve impulses to the adrenal medulla), releasing catecholamines for immediate fight-or-flight. The HPA axis activates over minutes to hours, producing cortisol for sustained metabolic support. Both systems work synergistically during stress.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-10", type: "question", question: "Cortisol affects wound healing by:", options: ["Accelerating collagen synthesis", "Inhibiting fibroblast proliferation, collagen synthesis, and inflammatory mediators — delaying wound healing in chronically stressed patients", "Promoting angiogenesis", "Having no effect on wound healing"], correctIndex: 1, answer: "Elevated cortisol impairs wound healing through multiple mechanisms: suppression of fibroblast proliferation (reduced collagen production), inhibition of inflammatory mediators (impaired initial wound response), reduced angiogenesis, and decreased epithelialization. This is why chronically stressed or corticosteroid-treated patients heal poorly.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-11", type: "question", question: "The dexamethasone suppression test evaluates:", options: ["Thyroid function", "HPA axis feedback — failure to suppress cortisol after dexamethasone indicates HPA axis dysregulation (Cushing syndrome)", "Adrenal medulla function", "Glucose tolerance"], correctIndex: 1, answer: "Dexamethasone is a potent synthetic glucocorticoid. In a normal HPA axis, exogenous dexamethasone suppresses CRH and ACTH via negative feedback, lowering cortisol. Failure to suppress indicates autonomous cortisol production (adrenal tumor), ectopic ACTH production, or pituitary Cushing disease.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-12", type: "question", question: "Cortisol excess causes central obesity because:", options: ["It decreases appetite", "It promotes visceral adipose tissue deposition through increased lipogenesis in truncal fat and increased appetite/caloric intake", "It increases muscle mass", "It causes peripheral fat storage only"], correctIndex: 1, answer: "Cortisol preferentially drives visceral (central) fat deposition through enhanced lipogenesis in abdominal adipocytes, increased appetite (especially for high-calorie foods), and insulin resistance. The resulting central obesity, combined with peripheral muscle wasting, creates the classic Cushingoid appearance.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-13", type: "question", question: "Stress-induced hyperglycemia in critically ill patients is caused by:", options: ["Insulin overdose", "Cortisol and catecholamines increasing hepatic gluconeogenesis and inducing peripheral insulin resistance", "Excessive carbohydrate intake", "Pancreatic beta cell destruction"], correctIndex: 1, answer: "Stress hormones (cortisol, epinephrine, norepinephrine, glucagon, growth hormone) collectively increase hepatic glucose production and induce peripheral insulin resistance. This adaptive response ensures glucose availability for vital organs but can cause dangerous hyperglycemia requiring insulin management in ICU patients.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-14", type: "question", question: "A patient on chronic corticosteroids who needs surgery requires:", options: ["No special preparation", "Stress-dose corticosteroids (hydrocortisone 100mg IV before induction) to prevent adrenal crisis from the surgical stress response", "Discontinuation of all steroids before surgery", "Double oral dose the morning of surgery"], correctIndex: 1, answer: "Patients with HPA axis suppression from chronic steroid use cannot mount an adequate cortisol response to surgical stress. Stress-dose hydrocortisone (100mg IV before induction, then 50mg IV q8h for 24-48h, then rapid taper) prevents perioperative adrenal crisis (refractory hypotension, cardiovascular collapse).", category: "Endocrine", difficulty: 2, clinicalPearl: "The '5-7.5-3' rule: >7.5mg prednisone daily for >3 weeks = assume HPA suppression; stress-dose steroids needed for major surgery." },
  { id: "rn-patho-hpa-15", type: "question", question: "Chronic HPA axis activation increases the risk of:", options: ["Improved memory", "Depression, metabolic syndrome, osteoporosis, and immunosuppression", "Enhanced wound healing", "Decreased blood pressure"], correctIndex: 1, answer: "Chronic cortisol elevation damages hippocampal neurons (impairing memory and increasing depression risk), promotes visceral obesity and insulin resistance (metabolic syndrome), increases bone resorption (osteoporosis), and suppresses immune function (infection susceptibility). This links chronic psychological stress to multiple medical conditions.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-16", type: "question", question: "The cosyntropin (ACTH stimulation) test diagnoses:", options: ["Hyperthyroidism", "Adrenal insufficiency — failure of cortisol to rise above 18-20 mcg/dL after synthetic ACTH injection indicates inadequate adrenal reserve", "Diabetes mellitus", "Pheochromocytoma"], correctIndex: 1, answer: "Cosyntropin (synthetic ACTH1-24) is injected IV/IM, and serum cortisol is measured at 30 and 60 minutes. A peak cortisol ≥18-20 mcg/dL indicates adequate adrenal reserve. A blunted response confirms adrenal insufficiency (primary or secondary with adrenal atrophy from prolonged ACTH deficiency).", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-17", type: "question", question: "Cortisol maintains cardiovascular stability during stress by:", options: ["Decreasing blood pressure", "Permitting catecholamine action on blood vessels (permissive effect) and maintaining vascular smooth muscle tone and responsiveness to vasopressors", "Causing vasodilation", "Decreasing heart rate"], correctIndex: 1, answer: "Cortisol has a critical permissive effect on catecholamine action: without adequate cortisol, blood vessels lose responsiveness to epinephrine and norepinephrine, causing refractory hypotension. This is why adrenal crisis presents with vasopressor-resistant shock — cortisol replacement restores vascular tone.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-18", type: "question", question: "Allostatic load refers to:", options: ["Normal stress response", "The cumulative physiologic wear from chronic stress — repeated HPA axis activation causes progressive tissue damage and disease", "A single acute stressor", "Post-traumatic stress recovery"], correctIndex: 1, answer: "Allostatic load is the cumulative burden of chronic stress on the body. Repeated HPA axis activation, sustained cortisol elevation, and chronic sympathetic activation cause progressive damage to the cardiovascular system, immune system, brain, and metabolism, increasing the risk of chronic disease.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-19", type: "question", question: "In sepsis, cortisol requirements increase because:", options: ["Patients are less stressed during sepsis", "The massive inflammatory response demands increased cortisol for immune modulation, hemodynamic stability, and metabolic support", "Cortisol has no role in sepsis", "Antibiotics require cortisol for activation"], correctIndex: 1, answer: "During sepsis, cortisol demand increases dramatically: it modulates the inflammatory cascade (preventing cytokine storm), maintains vascular tone (permissive effect on catecholamines), supports cardiac contractility, and provides metabolic substrates. Relative cortisol deficiency in sepsis contributes to refractory shock.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-20", type: "question", question: "Mineralocorticoid (aldosterone) secretion during stress:", options: ["Decreases", "Increases to promote sodium and water retention, maintaining intravascular volume and blood pressure during the stress response", "Is not affected by stress", "Causes potassium retention"], correctIndex: 1, answer: "Stress activates the RAAS (renin-angiotensin-aldosterone system) in addition to the HPA axis. Aldosterone promotes sodium and water reabsorption in the collecting duct, maintaining intravascular volume and blood pressure. It also promotes potassium excretion, which can cause hypokalemia during prolonged stress.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-21", type: "question", question: "Cortisol affects bone metabolism by:", options: ["Promoting bone formation", "Inhibiting osteoblast function, promoting osteoclast activity, and decreasing intestinal calcium absorption — leading to osteoporosis with chronic elevation", "Having no effect on bone", "Increasing vitamin D activation"], correctIndex: 1, answer: "Chronic cortisol elevation causes osteoporosis through: direct inhibition of osteoblasts (reduced bone formation), indirect promotion of osteoclast activity (via increased RANKL/decreased OPG), decreased intestinal calcium absorption, and increased renal calcium excretion. Glucocorticoid-induced osteoporosis is the most common secondary cause.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-hpa-22", type: "question", question: "A steroid taper is necessary because:", options: ["Steroids taste better in decreasing doses", "Gradual dose reduction allows the suppressed HPA axis to recover endogenous cortisol production, preventing adrenal crisis from abrupt withdrawal", "Tapering is just a preference", "There are no side effects from abrupt discontinuation"], correctIndex: 1, answer: "After chronic exogenous corticosteroid use (>3 weeks at >7.5mg prednisone equivalent), the HPA axis is suppressed and adrenals are atrophied. Tapering gradually reduces the exogenous dose, allowing CRH and ACTH secretion to resume and adrenal cortex function to recover. This process may take weeks to months.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-hpa-23", type: "question", question: "Cortisol's effect on fluid balance includes:", options: ["Promoting diuresis", "Enhancing free water clearance (weak mineralocorticoid effect) and maintaining glomerular filtration rate — cortisol deficiency causes hyponatremia and fluid retention", "Causing edema through sodium loss", "No effect on fluid balance"], correctIndex: 1, answer: "Cortisol has a weak mineralocorticoid effect (sodium retention) and is essential for free water clearance by maintaining normal GFR and suppressing ADH. In cortisol deficiency, impaired free water clearance and increased ADH cause dilutional hyponatremia, a hallmark of adrenal insufficiency.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-hpa-24", type: "question", question: "The nurse teaches a patient on chronic prednisone to:", options: ["Stop medication whenever they feel better", "Never stop abruptly, carry a medical alert identification, and increase dose during illness or stress (sick-day rules)", "Take the medication only when symptomatic", "Double the dose every week"], correctIndex: 1, answer: "Key teaching: (1) NEVER stop abruptly — taper under provider guidance; (2) carry medical alert ID stating steroid dependence; (3) sick-day rules — notify provider during illness, may need increased dose; (4) stress dosing — may need supplemental doses during surgery or trauma; (5) monitor for Cushingoid side effects.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-hpa-25", type: "question", question: "Diurnal cortisol variation shows:", options: ["Highest levels at midnight", "Highest levels in early morning (6-8 AM), lowest at midnight — this circadian pattern is disrupted in Cushing syndrome and chronic stress", "Constant levels throughout the day", "Highest levels after dinner"], correctIndex: 1, answer: "Normal cortisol follows a circadian rhythm: peak in early morning (preparing for the day's energy demands), declining throughout the day, lowest around midnight. Loss of this diurnal variation (persistently elevated midnight cortisol) is a sensitive indicator of Cushing syndrome or chronic HPA axis dysregulation.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-14", type: "question", question: "In primary adrenal insufficiency, ACTH is elevated because:", options: ["The adrenal glands are overproducing cortisol", "Damaged adrenals cannot produce cortisol, removing negative feedback on the pituitary, causing ACTH to rise markedly", "The pituitary gland is damaged", "Exogenous steroids are suppressing the axis"], correctIndex: 1, answer: "In Addison disease (primary AI), the adrenal cortex is destroyed (autoimmune, infection, hemorrhage). Without cortisol production, negative feedback on the hypothalamus and pituitary is lost, causing compensatory CRH and ACTH elevation. ACTH elevation also causes hyperpigmentation via MSH activity.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-15", type: "question", question: "The classic electrolyte findings in primary adrenal insufficiency are:", options: ["Hypernatremia and hypokalemia", "Hyponatremia and hyperkalemia — from aldosterone deficiency causing sodium loss and potassium retention", "Normal sodium and potassium", "Hypernatremia and hyperkalemia"], correctIndex: 1, answer: "Aldosterone deficiency (from adrenal cortex destruction) causes impaired sodium reabsorption (hyponatremia, volume depletion) and impaired potassium excretion (hyperkalemia) in the collecting duct. These electrolyte changes are classic for PRIMARY adrenal insufficiency but NOT secondary (pituitary) where aldosterone is preserved via RAAS.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-16", type: "question", question: "Waterhouse-Friderichsen syndrome is:", options: ["A chronic condition", "Acute bilateral adrenal hemorrhage, usually from meningococcal sepsis, causing acute adrenal crisis with refractory shock, purpura fulminans, and DIC", "A thyroid disorder", "A pituitary tumor syndrome"], correctIndex: 1, answer: "Waterhouse-Friderichsen syndrome is a catastrophic complication of meningococcal septicemia. Bacterial endotoxins cause bilateral adrenal hemorrhagic necrosis, resulting in acute cortisol and aldosterone deficiency. The combination of septic shock PLUS adrenal crisis causes rapidly fatal cardiovascular collapse if not immediately treated.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-adrenal-17", type: "question", question: "When a patient in adrenal crisis is hypotensive and unresponsive to IV fluids, the nurse should anticipate:", options: ["More IV fluids only", "IV hydrocortisone 100mg bolus — cortisol is required for vascular responsiveness to catecholamines and vasopressors", "Oral prednisone", "Withholding all medications"], correctIndex: 1, answer: "Adrenal crisis causes vasopressor-resistant hypotension because cortisol is required for vascular smooth muscle responsiveness to catecholamines (permissive effect). IV hydrocortisone 100mg bolus is life-saving — it restores vascular tone within 1-2 hours. Hydrocortisone also has mineralocorticoid activity for volume support.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-18", type: "question", question: "Hyperpigmentation in Addison disease is caused by:", options: ["Sun exposure", "Elevated ACTH and its precursor POMC, which contains melanocyte-stimulating hormone (MSH) — causing darkening of skin creases, scars, and mucous membranes", "Iron deposits", "Medication side effects"], correctIndex: 1, answer: "ACTH is cleaved from pro-opiomelanocortin (POMC), which also contains MSH. When ACTH is markedly elevated (from loss of cortisol feedback), increased POMC processing produces excess MSH, causing characteristic hyperpigmentation in skin creases, palmar creases, buccal mucosa, scars, and nipples.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-19", type: "question", question: "Secondary adrenal insufficiency differs from primary in that:", options: ["Both present identically", "Secondary AI (pituitary ACTH deficiency) preserves aldosterone secretion (RAAS-controlled), causes NO hyperpigmentation (low ACTH), and has no hyperkalemia", "Secondary AI causes more hyperpigmentation", "Secondary AI has higher ACTH levels"], correctIndex: 1, answer: "In secondary AI, pituitary ACTH is deficient (not elevated), so: (1) no hyperpigmentation (MSH is not elevated), (2) aldosterone is preserved (regulated by RAAS, not ACTH), so no hyperkalemia, (3) cortisol deficiency IS present. The most common cause is chronic exogenous steroid use causing pituitary ACTH suppression.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-20", type: "question", question: "Fludrocortisone is prescribed for Addison disease to:", options: ["Replace cortisol", "Replace aldosterone — it is a synthetic mineralocorticoid that promotes sodium retention and potassium excretion", "Treat hyperpigmentation", "Suppress ACTH"], correctIndex: 1, answer: "Fludrocortisone is a synthetic mineralocorticoid that replaces the aldosterone deficiency in primary AI. It acts on the collecting duct to promote sodium reabsorption and potassium excretion, maintaining blood pressure and electrolyte balance. Monitor for hypertension, edema, and hypokalemia.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-21", type: "question", question: "A patient with Addison disease develops gastroenteritis with vomiting and diarrhea. The nurse's priority concern is:", options: ["Dehydration only", "Precipitating adrenal crisis — the patient cannot absorb oral hydrocortisone and the physiologic stress of illness increases cortisol demand", "Electrolyte imbalance from vomiting", "Dietary changes"], correctIndex: 1, answer: "Vomiting prevents absorption of oral replacement hydrocortisone while the physiologic stress of illness dramatically increases cortisol demand. This mismatch precipitates adrenal crisis. The patient needs emergency IM/IV hydrocortisone (stress dosing), IV fluids, and likely ED evaluation.", category: "Endocrine", difficulty: 2, clinicalPearl: "Teach all Addison patients to have an emergency injection kit with IM hydrocortisone (100mg) and train family members to administer it." },
  { id: "rn-patho-adrenal-22", type: "question", question: "Morning cortisol below 3 mcg/dL is:", options: ["Normal", "Strongly suggestive of adrenal insufficiency and should prompt cosyntropin stimulation testing", "Only concerning if symptomatic", "Expected in elderly patients"], correctIndex: 1, answer: "Morning cortisol <3 mcg/dL is highly suggestive of adrenal insufficiency (normal 6-23 mcg/dL, highest in early AM). A cosyntropin stimulation test confirms the diagnosis: if cortisol fails to rise above 18-20 mcg/dL after synthetic ACTH injection, adrenal insufficiency is confirmed.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-adrenal-23", type: "question", question: "Salt craving in Addison disease is caused by:", options: ["Psychological preference", "Aldosterone deficiency causing excessive renal sodium wasting, triggering physiologic sodium hunger", "Cortisol excess", "Dehydration only"], correctIndex: 1, answer: "Aldosterone deficiency in primary AI impairs renal sodium reabsorption, causing chronic sodium loss (hyponatremia). The body compensates with intense salt craving — a physiologic drive to replace lost sodium. This is a classic symptom that helps distinguish primary from secondary AI (aldosterone is preserved in secondary).", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-24", type: "question", question: "Patients with adrenal insufficiency should increase their hydrocortisone dose during:", options: ["Mild headaches", "Physical illness (fever, infection), surgery, trauma, or significant emotional stress — 2-3x the usual dose during minor illness, stress-dose for major events", "Routine exercise", "Normal daily activities"], correctIndex: 1, answer: "Stress dosing rules: (1) Minor illness (cold, mild fever): double or triple the oral dose; (2) Major illness/surgery: IM/IV hydrocortisone 100mg then 50mg q8h; (3) Resume normal dosing when stress resolves. Without stress dosing, the patient cannot mount an adequate cortisol response and may develop adrenal crisis.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-adrenal-25", type: "question", question: "Adrenal crisis can present with which life-threatening findings?", options: ["Hypertension and bradycardia", "Refractory hypotension, severe hyponatremia, hyperkalemia, hypoglycemia, and altered consciousness progressing to cardiovascular collapse", "Fever and rash only", "Increased urine output"], correctIndex: 1, answer: "Adrenal crisis is a medical emergency: refractory hypotension (loss of cortisol's permissive vascular effect), severe hyponatremia (impaired free water clearance), hyperkalemia (aldosterone deficiency in primary AI), hypoglycemia (loss of cortisol-mediated gluconeogenesis), and altered consciousness. Untreated, it progresses to cardiovascular collapse and death.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-leuk-14", type: "question", question: "Philadelphia chromosome-positive ALL has which translocation?", options: ["t(9;22)", "t(15;17)", "t(8;21)", "t(14;18)"], correctIndex: 0, answer: "The Philadelphia chromosome results from t(9;22) translocation creating the BCR-ABL1 fusion gene. In ALL, Ph+ status occurs in approximately 25% of adult cases and confers a worse prognosis. Tyrosine kinase inhibitors (imatinib, dasatinib) are added to chemotherapy for Ph+ ALL.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-15", type: "question", question: "Auer rods on peripheral smear are pathognomonic for:", options: ["ALL", "AML — crystallized aggregates of myeloperoxidase-positive granules in myeloid blast cells", "CLL", "Lymphoma"], correctIndex: 1, answer: "Auer rods are needle-shaped cytoplasmic inclusions found in myeloid blasts, pathognomonic for AML. They represent crystallized azurophilic granules containing myeloperoxidase, acid phosphatase, and esterase. Their presence distinguishes AML from ALL on morphology.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-16", type: "question", question: "Tumor lysis syndrome (TLS) in leukemia is characterized by:", options: ["Hypocalcemia, hyperkalemia, hyperphosphatemia, and hyperuricemia — from rapid cell lysis releasing intracellular contents", "Hypercalcemia and hypokalemia", "Normal electrolytes", "Elevated hemoglobin"], correctIndex: 0, answer: "TLS occurs when rapid cancer cell death releases intracellular contents: potassium (hyperkalemia → cardiac arrhythmias), phosphate (hyperphosphatemia → calcium precipitation → hypocalcemia), uric acid (hyperuricemia → renal failure), and nucleic acids. Prevention: aggressive hydration, allopurinol or rasburicase.", category: "Hematology", difficulty: 2, clinicalPearl: "High-risk: ALL, Burkitt lymphoma, high WBC count AML. Start prevention 24-48h before chemotherapy." },
  { id: "rn-patho-leuk-17", type: "question", question: "CNS prophylaxis in ALL is necessary because:", options: ["The brain produces leukemia cells", "The blood-brain barrier protects leukemia cells from systemic chemotherapy, making the CNS a sanctuary site for disease relapse", "ALL never involves the CNS", "Cranial radiation is routine for all cancers"], correctIndex: 1, answer: "The blood-brain barrier prevents most systemic chemotherapy agents from reaching therapeutic concentrations in the CNS. Without intrathecal chemotherapy (methotrexate, cytarabine) and/or cranial radiation, leukemia cells hiding in the CNS will cause relapse. CNS prophylaxis dramatically improved ALL survival.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-18", type: "question", question: "DIC is a common complication of which leukemia subtype?", options: ["ALL", "AML-M3 (acute promyelocytic leukemia) — abnormal promyelocytes release procoagulant granules causing consumptive coagulopathy", "CML", "CLL"], correctIndex: 1, answer: "APL (AML-M3, t(15;17)) is notorious for triggering DIC. Abnormal promyelocytes contain granules with tissue factor and other procoagulants that activate the clotting cascade when released (cell lysis from disease or chemotherapy). This causes simultaneous thrombosis and hemorrhage.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-19", type: "question", question: "ATRA (all-trans retinoic acid) is the cornerstone treatment for:", options: ["ALL", "AML-M3 (APL) — it induces differentiation of abnormal promyelocytes into mature granulocytes", "CML", "Any AML subtype"], correctIndex: 1, answer: "ATRA binds to the PML-RARα fusion protein (from t(15;17)) and forces abnormal promyelocytes to differentiate into mature granulocytes. This differentiation therapy (rather than cytotoxic killing) transformed APL from the most fatal to the most curable AML subtype (>90% cure rate with ATRA + arsenic trioxide).", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-20", type: "question", question: "Leukostasis is a medical emergency occurring when:", options: ["WBC is slightly elevated", "Extremely high WBC count (>100,000/μL) causes hyperviscosity with sludging in cerebral and pulmonary microvasculature, causing stroke-like symptoms and respiratory failure", "Platelets are low", "RBC count is elevated"], correctIndex: 1, answer: "Leukostasis occurs with hyperleukocytosis (WBC >100,000), most commonly in AML. Large, sticky myeloid blasts occlude microvasculature, causing tissue ischemia. Symptoms: dyspnea, hypoxia, headache, confusion, visual changes, stroke-like symptoms. Treatment: emergent leukapheresis and hydroxyurea to rapidly reduce WBC.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-21", type: "question", question: "Post-chemotherapy nadir refers to:", options: ["The peak WBC count", "The lowest point of blood cell counts (especially neutrophils) after chemotherapy, typically occurring 7-14 days post-treatment — the period of highest infection risk", "The recovery phase", "Normal blood counts"], correctIndex: 1, answer: "The nadir is the point of maximum bone marrow suppression after chemotherapy, when WBC (especially neutrophils), RBC, and platelets are at their lowest. For most regimens, nadir occurs 7-14 days post-treatment. Neutrophil recovery typically begins around day 14-21. This is when infection risk is highest.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-leuk-22", type: "question", question: "CAR-T cell therapy works by:", options: ["Giving chemotherapy directly", "Engineering the patient's own T cells to express chimeric antigen receptors that target specific cancer surface proteins (e.g., CD19 on B-cell ALL)", "Transplanting donor bone marrow", "Administering antibodies"], correctIndex: 1, answer: "CAR-T therapy: (1) harvest patient's T cells (leukapheresis), (2) genetically engineer them to express chimeric antigen receptors (CARs) targeting cancer antigens (CD19 for B-ALL), (3) multiply in lab, (4) infuse back into patient. The engineered T cells recognize and kill cancer cells. Major risk: cytokine release syndrome.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-leuk-23", type: "question", question: "Graft-versus-host disease (GVHD) after allogeneic stem cell transplant occurs because:", options: ["The patient rejects the donor cells", "Donor T cells recognize the recipient's tissues as foreign and attack them — affecting skin, liver, and GI tract", "The graft fails to engraft", "Chemotherapy side effects persist"], correctIndex: 1, answer: "GVHD: donor-derived T cells (in the graft) recognize recipient HLA antigens as foreign and mount an immune attack against host tissues. Acute GVHD (<100 days): skin rash, hepatitis, diarrhea. Chronic GVHD (>100 days): scleroderma-like skin changes, sicca syndrome, bronchiolitis obliterans.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-leuk-24", type: "question", question: "Febrile neutropenia is defined as:", options: ["Any fever", "Temperature ≥38.3°C (100.9°F) single, or ≥38.0°C sustained for 1 hour, with ANC <500/μL — a medical emergency requiring immediate blood cultures and empiric broad-spectrum antibiotics", "Low-grade fever with normal WBC", "Fever after blood transfusion"], correctIndex: 1, answer: "Febrile neutropenia is a medical emergency: infection can progress to sepsis and death within hours in neutropenic patients who lack immune defenses. Treatment: immediate blood cultures (do NOT delay antibiotics for culture results), then empiric broad-spectrum IV antibiotics (e.g., cefepime, piperacillin-tazobactam, or meropenem).", category: "Hematology", difficulty: 1, clinicalPearl: "Time to antibiotics is critical: every hour of delay increases mortality. Goal: antibiotics within 60 minutes of presentation." },
  { id: "rn-patho-leuk-25", type: "question", question: "Minimal residual disease (MRD) testing in leukemia:", options: ["Is not useful clinically", "Detects tiny amounts of remaining leukemia cells (as few as 1 in 10,000-100,000 cells) using flow cytometry or PCR, guiding treatment decisions and predicting relapse risk", "Only detects large numbers of cancer cells", "Is only done at diagnosis"], correctIndex: 1, answer: "MRD testing can detect leukemia cells below the threshold of conventional morphology (which requires >5% blasts). MRD-negative status after induction is a strong prognostic indicator. MRD-positive patients may need treatment intensification, transplant, or novel therapies to prevent relapse.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-sickle-7", type: "question", question: "Sickle cell trait (HbAS) differs from sickle cell disease (HbSS) in that:", options: ["Both are equally severe", "Trait carriers have one normal and one sickle gene, rarely experience sickling (only under extreme hypoxia), and are generally asymptomatic", "Trait carriers have more crises", "There is no difference"], correctIndex: 1, answer: "HbAS (trait): one normal β-globin gene produces enough HbA (50-60%) to prevent significant sickling under normal conditions. Rarely causes symptoms except under extreme conditions (high altitude, severe dehydration, extreme exercise). HbSS (disease): both genes are affected, causing >80% HbS with chronic hemolysis and vaso-occlusive crises.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-sickle-8", type: "question", question: "Hydroxyurea benefits sickle cell patients by:", options: ["Replacing sickled cells", "Increasing fetal hemoglobin (HbF) production, which interferes with HbS polymerization and reduces sickling", "Providing iron supplementation", "Curing sickle cell disease"], correctIndex: 1, answer: "Hydroxyurea reactivates fetal hemoglobin (HbF) gene expression. HbF (α2γ2) cannot participate in HbS polymerization, so increased HbF dilutes HbS concentration within RBCs, reducing sickling. Benefits: fewer vaso-occlusive crises, reduced ACS episodes, decreased transfusion needs, and improved survival.", category: "Hematology", difficulty: 2, clinicalPearl: "Monitor CBC regularly — hydroxyurea causes bone marrow suppression. Hold if ANC <2000 or platelets <80,000." },
  { id: "rn-patho-sickle-9", type: "question", question: "Acute chest syndrome (ACS) in sickle cell disease is characterized by:", options: ["Mild cough only", "New pulmonary infiltrate on chest X-ray PLUS one or more: chest pain, fever, respiratory symptoms, hypoxia — it is the leading cause of death in SCD", "Normal chest X-ray with dyspnea", "Only occurs in children"], correctIndex: 1, answer: "ACS is defined by a NEW pulmonary infiltrate plus respiratory symptoms. Causes include pulmonary vascular occlusion by sickled cells, fat embolism from infarcted bone marrow, and infection. Treatment: exchange transfusion (severe cases), antibiotics (atypical coverage), oxygen, bronchodilators, and incentive spirometry.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-10", type: "question", question: "Splenic sequestration crisis in sickle cell disease presents with:", options: ["Small spleen", "Rapid splenic enlargement, severe anemia (Hgb drop >2g/dL), thrombocytopenia, and hypovolemic shock — most common in children under 5", "Normal hemoglobin", "Elevated platelets"], correctIndex: 1, answer: "Splenic sequestration: sickled RBCs obstruct splenic venous outflow, causing blood pooling within the spleen. The spleen enlarges rapidly, sequestering large blood volumes. This causes acute severe anemia, thrombocytopenia, and potentially fatal hypovolemic shock. Treatment: immediate fluid resuscitation and transfusion.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-11", type: "question", question: "Priapism in sickle cell disease is caused by:", options: ["Increased testosterone", "Vaso-occlusion of penile venous outflow by sickled cells, causing prolonged painful erection lasting >4 hours — a urologic emergency requiring aspiration and irrigation", "Medication side effect", "Normal physiologic response"], correctIndex: 1, answer: "Ischemic (low-flow) priapism occurs when sickled RBCs obstruct penile corporal venous drainage. Prolonged ischemia (>4 hours) causes irreversible tissue damage leading to erectile dysfunction. Treatment: aspiration and irrigation of corpora cavernosa, phenylephrine injection, exchange transfusion for refractory cases.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-12", type: "question", question: "Aplastic crisis in sickle cell disease is usually triggered by:", options: ["Iron deficiency", "Parvovirus B19 infection — it selectively infects erythroid progenitor cells, halting RBC production for 7-10 days", "Dehydration", "Cold exposure"], correctIndex: 1, answer: "Parvovirus B19 has tropism for erythroid progenitor cells (via the P antigen receptor). In normal individuals, the 7-10 day RBC production halt is insignificant. In SCD patients (who have chronic hemolysis with RBC lifespan of 10-20 days vs normal 120 days), this brief halt causes severe aplastic anemia with reticulocyte count near zero.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-13", type: "question", question: "Sickle cell patients should avoid:", options: ["Hydration", "Dehydration, high altitude, extreme cold, strenuous exercise, and unpressurized aircraft — all trigger sickling by causing hypoxia, acidosis, or dehydration", "Folic acid supplementation", "Routine immunizations"], correctIndex: 1, answer: "Sickling triggers: (1) dehydration → increased HbS concentration; (2) hypoxia (high altitude, unpressurized aircraft) → HbS polymerization; (3) cold → vasoconstriction → stasis; (4) acidosis → right-shifts oxygen-hemoglobin curve → deoxygenation; (5) strenuous exercise → hypoxia + dehydration + acidosis. Teaching prevention is crucial.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-sickle-14", type: "question", question: "Chronic hemolysis in SCD leads to iron overload requiring:", options: ["More iron supplements", "Chelation therapy (deferasirox, deferoxamine) for patients receiving chronic transfusions — excess iron deposits in heart, liver, and endocrine organs cause organ damage", "No treatment", "Phlebotomy"], correctIndex: 1, answer: "Each unit of PRBCs contains 200-250mg of iron. The body has no mechanism to excrete excess iron. After approximately 20 transfusions, iron overload begins damaging the heart (cardiomyopathy), liver (cirrhosis), and endocrine organs (diabetes, hypogonadism). Serum ferritin >1000 ng/mL triggers chelation therapy initiation.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-15", type: "question", question: "Transcranial Doppler (TCD) screening in children with SCD is used to:", options: ["Diagnose hearing loss", "Identify children at high risk for stroke by detecting elevated cerebral blood flow velocities >200 cm/sec — chronic transfusion therapy reduces stroke risk by 92%", "Monitor cardiac function", "Assess renal function"], correctIndex: 1, answer: "SCD causes progressive cerebral vasculopathy. TCD detects increased blood flow velocity in stenotic cerebral arteries. Velocities >200 cm/sec indicate high stroke risk (up to 10%/year without intervention). Chronic transfusion to maintain HbS <30% reduces stroke risk by 92%. Screening starts at age 2 and continues annually.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-sickle-16", type: "question", question: "Pain management in vaso-occlusive crisis should include:", options: ["NSAIDs only", "Multimodal approach: IV opioids (patient-controlled analgesia), NSAIDs, hydration, oxygen if hypoxic, and heat application — assess pain using validated scales every 30-60 minutes", "Avoid opioids due to addiction risk", "Pain medication only when patient requests it"], correctIndex: 1, answer: "VOC pain is severe (often 10/10) and requires aggressive multimodal management. IV opioids (hydromorphone or morphine via PCA) are first-line. Add NSAIDs/acetaminophen for synergy. Adequate hydration (1.5x maintenance) reduces sickling. Reassess pain frequently. Avoid stigmatizing patients — SCD pain is genuine and severe.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-sickle-17", type: "question", question: "Voxelotor works in sickle cell disease by:", options: ["Providing iron", "Binding to hemoglobin S and increasing its oxygen affinity, stabilizing the oxygenated state and preventing polymerization", "Replacing sickle hemoglobin", "Stimulating WBC production"], correctIndex: 1, answer: "Voxelotor (Oxbryta) is a hemoglobin S polymerization inhibitor. It binds to the alpha chain of HbS, increasing oxygen affinity and stabilizing the relaxed (R-state) oxygenated conformation. This prevents the deoxygenated T-state transition that initiates HbS polymerization and sickling. It improves hemoglobin and reduces hemolysis markers.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-sickle-18", type: "question", question: "Functional asplenia in SCD occurs by age:", options: ["1 year", "5 years — repeated splenic infarction from sickling causes autosplenectomy, making patients vulnerable to encapsulated bacteria (pneumococcus, meningococcus, Haemophilus)", "20 years", "50 years"], correctIndex: 1, answer: "By age 5, most HbSS patients have functional asplenia from repeated splenic infarction (autosplenectomy). Without splenic immune function, patients are extremely vulnerable to encapsulated organisms. Required immunizations: pneumococcal (PCV13 + PPSV23), meningococcal, Haemophilus influenzae type B. Prophylactic penicillin until at least age 5.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-19", type: "question", question: "Exchange transfusion in SCD is preferred over simple transfusion when:", options: ["For all transfusions", "For acute stroke, severe ACS, or preoperative preparation — it rapidly reduces HbS percentage to <30% without causing hyperviscosity from volume overload", "Only for children", "For routine chronic transfusions"], correctIndex: 1, answer: "Exchange transfusion (automated erythrocytapheresis) removes patient's sickled blood and replaces with donor blood, rapidly reducing HbS percentage. Advantages over simple transfusion: avoids hyperviscosity from increased hematocrit, reduces iron loading, and achieves target HbS <30% more quickly. Indicated for stroke, severe ACS, and multi-organ failure.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-thal-7", type: "question", question: "In beta-thalassemia major, why do patients develop hepatosplenomegaly?", options: ["Liver disease from alcohol", "Extramedullary hematopoiesis — the liver and spleen attempt to compensate for ineffective bone marrow erythropoiesis by producing RBCs themselves", "Viral hepatitis", "Heart failure only"], correctIndex: 1, answer: "In thalassemia major, severe ineffective erythropoiesis in the bone marrow leads to compensatory extramedullary hematopoiesis (RBC production in liver and spleen). Additionally, chronic hemolysis causes splenic enlargement from RBC trapping, and iron overload causes hepatomegaly.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-8", type: "question", question: "Cooley facies in beta-thalassemia major is caused by:", options: ["Malnutrition", "Massive bone marrow expansion from compensatory erythropoiesis — causing frontal bossing, maxillary overgrowth, and widened diploic space on skull X-ray ('hair-on-end' appearance)", "Genetic facial features", "Medication side effects"], correctIndex: 1, answer: "The severely anemic bone marrow in thalassemia major expands dramatically in an attempt to increase RBC production. This medullary expansion causes: frontal and parietal bossing, maxillary overgrowth (chipmunk facies), widened diploic space ('hair-on-end' on skull X-ray), and pathologic fractures from cortical thinning.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-9", type: "question", question: "The target hemoglobin for transfusion in beta-thalassemia major is:", options: ["6-7 g/dL", "9-10 g/dL (pre-transfusion >9.5 g/dL) — maintaining adequate hemoglobin suppresses ineffective erythropoiesis and its complications", "12-14 g/dL", "There is no target"], correctIndex: 1, answer: "Regular transfusions maintain pre-transfusion Hgb >9.5 g/dL. This suppresses endogenous (ineffective) erythropoiesis, preventing bone marrow expansion (skeletal deformities), extramedullary hematopoiesis (hepatosplenomegaly), and excessive iron absorption. The transfusion-related iron loading requires concurrent chelation therapy.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-10", type: "question", question: "Iron chelation in thalassemia major is necessary because:", options: ["Patients are iron deficient", "Chronic transfusions cause iron overload — each unit of PRBCs adds 200-250mg iron, and the body has no mechanism to excrete excess iron, which deposits in heart, liver, and endocrine organs", "Iron improves hemoglobin production", "Chelation is optional"], correctIndex: 1, answer: "Without chelation, transfusion-dependent thalassemia patients accumulate 0.3-0.5mg/kg/day of iron. Iron deposits in the heart (cardiomyopathy — leading cause of death), liver (cirrhosis), pancreas (diabetes), pituitary (hypogonadism), and thyroid (hypothyroidism). Chelation (deferasirox, deferoxamine, deferiprone) is life-saving.", category: "Hematology", difficulty: 2, clinicalPearl: "Cardiac T2* MRI monitors cardiac iron loading — values <20ms indicate iron overload, <10ms indicate severe cardiac risk requiring intensified chelation." },
  { id: "rn-patho-thal-11", type: "question", question: "Alpha-thalassemia with deletion of all four alpha-globin genes causes:", options: ["Mild anemia", "Hydrops fetalis (Bart hemoglobin) — incompatible with life, causing in utero death from severe anemia and heart failure", "Thalassemia trait", "No clinical significance"], correctIndex: 1, answer: "Loss of all 4 α-globin genes (--/--) prevents α-globin production entirely. Without α chains, excess γ chains form Hb Bart (γ4), which has extremely high oxygen affinity and cannot deliver oxygen to tissues. The fetus develops severe anemia, heart failure, hydrops fetalis, and death in utero or shortly after birth.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-thal-12", type: "question", question: "HbH disease (3 alpha gene deletions) presents with:", options: ["No symptoms", "Moderate hemolytic anemia with HbH inclusions — HbH (β4 tetramers) is unstable and precipitates within RBCs, causing their destruction", "Severe hydrops fetalis", "Only affects carriers"], correctIndex: 1, answer: "With 3 α-gene deletions (-/-α), reduced α-chain production causes excess β chains to form β4 tetramers (HbH). HbH is unstable, precipitates within RBCs (visible as HbH inclusions on supravital staining), and causes oxidative damage leading to hemolysis. Patients have moderate anemia, jaundice, and splenomegaly.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-thal-13", type: "question", question: "Hemoglobin electrophoresis in beta-thalassemia minor shows:", options: ["Normal hemoglobin pattern", "Elevated HbA2 (>3.5%) and mildly elevated HbF — this is the diagnostic hallmark used to distinguish thalassemia trait from iron deficiency anemia", "Only HbS present", "Absent HbA"], correctIndex: 1, answer: "In β-thalassemia minor (trait), reduced β-chain production shifts hemoglobin production toward δ chains (HbA2 = α2δ2, elevated >3.5%) and γ chains (HbF = α2γ2, mildly elevated). Normal HbA2 is <3.5%. This distinguishes thalassemia trait from iron deficiency anemia, which has normal HbA2.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-14", type: "question", question: "Luspatercept (Reblozyl) is used in thalassemia to:", options: ["Replace iron", "Reduce transfusion burden by promoting late-stage erythroid maturation — it targets the TGF-β superfamily pathway to improve ineffective erythropoiesis", "Chelate iron", "Suppress the immune system"], correctIndex: 1, answer: "Luspatercept is a modified activin receptor that traps TGF-β superfamily ligands (GDF11, activin B) that normally inhibit late-stage erythroid differentiation. By blocking these inhibitory signals, luspatercept promotes erythroid maturation and reduces ineffective erythropoiesis, decreasing transfusion requirements in thalassemia.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-thal-15", type: "question", question: "A key nursing assessment for thalassemia patients on chronic transfusions includes:", options: ["Daily weight only", "Monitoring for transfusion reactions, assessing serum ferritin trends, and evaluating for signs of iron overload in target organs (heart failure, liver dysfunction, endocrine abnormalities)", "Checking blood glucose only", "No specific assessments needed"], correctIndex: 1, answer: "Chronic transfusion nursing priorities: (1) monitor for acute/delayed transfusion reactions each transfusion; (2) track serum ferritin (target <1000 ng/mL with chelation); (3) assess for iron overload signs: heart failure symptoms, liver function, endocrine function (growth, puberty, thyroid, glucose); (4) ensure chelation adherence.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-thal-16", type: "question", question: "Why should iron supplements be AVOIDED in thalassemia trait?", options: ["They are not available", "Thalassemia trait is often misdiagnosed as iron deficiency anemia — giving iron to an iron-replete thalassemia patient causes iatrogenic iron overload", "Iron worsens anemia in thalassemia", "Iron supplements are always beneficial"], correctIndex: 1, answer: "Thalassemia trait causes microcytic hypochromic anemia that mimics iron deficiency. However, thalassemia patients have normal or increased iron stores (increased intestinal absorption from ineffective erythropoiesis). Adding iron supplements to an iron-replete patient causes dangerous iron overload. Always check iron studies before treating microcytic anemia.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-thal-17", type: "question", question: "Genetic counseling in thalassemia is important because:", options: ["It is not important", "Two carriers (trait) have a 25% chance of having a child with thalassemia major — screening and counseling enable informed reproductive decisions", "Thalassemia cannot be inherited", "Only one parent needs to carry the gene"], correctIndex: 1, answer: "β-thalassemia follows autosomal recessive inheritance. When both parents carry β-thalassemia trait: 25% chance of thalassemia major (transfusion-dependent), 50% chance of trait, 25% chance of unaffected. Carrier screening, genetic counseling, and prenatal testing (CVS, amniocentesis) allow informed family planning decisions.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-pancy-7", type: "question", question: "Aplastic anemia is the most serious cause of pancytopenia because:", options: ["It only affects one cell line", "The bone marrow fails to produce ALL blood cell lines — replaced by fat, causing life-threatening anemia, neutropenia, and thrombocytopenia simultaneously", "It is easily treated", "It only affects elderly patients"], correctIndex: 1, answer: "In aplastic anemia, the hematopoietic stem cells are damaged or destroyed (autoimmune attack, toxins, radiation), replaced by fat. This causes simultaneous failure of all cell lines: severe anemia (fatigue, dyspnea), neutropenia (life-threatening infections), and thrombocytopenia (hemorrhage). Treatment: immunosuppression or stem cell transplant.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-8", type: "question", question: "Drug-induced pancytopenia is most commonly caused by:", options: ["Acetaminophen", "Chemotherapy agents, chloramphenicol, carbamazepine, methotrexate, and sulfonamides — through direct bone marrow toxicity or immune-mediated destruction", "Aspirin", "Beta-blockers"], correctIndex: 1, answer: "Many drugs can cause pancytopenia through dose-dependent myelosuppression (chemotherapy, methotrexate) or idiosyncratic reactions (chloramphenicol, carbamazepine, sulfonamides). The nurse should review all medications when evaluating unexplained pancytopenia. Discontinuation of the causative agent may allow marrow recovery.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-9", type: "question", question: "Bone marrow biopsy in pancytopenia evaluation is essential to:", options: ["Check hemoglobin level", "Determine cellularity (hypocellular vs hypercellular), identify infiltrative processes (leukemia, myelofibrosis, metastatic cancer), and assess for dysplasia (MDS)", "Measure serum iron", "Check electrolytes"], correctIndex: 1, answer: "Bone marrow biopsy differentiates causes: hypocellular marrow → aplastic anemia; hypercellular marrow → ineffective hematopoiesis (MDS, megaloblastic anemia) or peripheral destruction; infiltrated marrow → leukemia, lymphoma, myelofibrosis, metastatic cancer. Aspirate + biopsy together provide the most complete diagnostic picture.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-10", type: "question", question: "Myelodysplastic syndrome (MDS) causes pancytopenia through:", options: ["Bone marrow aplasia", "Ineffective hematopoiesis — the marrow is hypercellular but produces dysplastic, nonfunctional blood cells that undergo premature apoptosis", "Peripheral cell destruction only", "Nutritional deficiency"], correctIndex: 1, answer: "MDS: clonal stem cell disorder producing morphologically and functionally abnormal blood cells. The marrow is usually HYPERcellular (actively producing cells) but the cells are dysplastic and undergo intramedullary apoptosis (die before release). This paradox of hypercellular marrow with peripheral cytopenias is the hallmark of MDS.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-pancy-11", type: "question", question: "Nursing priorities for a pancytopenic patient include:", options: ["Routine care without precautions", "Strict neutropenic precautions, bleeding precautions, anemia management, and infection surveillance", "Isolation for tuberculosis only", "No special precautions needed"], correctIndex: 1, answer: "Triple-threat nursing care: (1) Neutropenia: neutropenic precautions, strict hand hygiene, no fresh flowers/fruits, monitor for subtle infection signs (may lack typical inflammatory response); (2) Thrombocytopenia: fall prevention, soft toothbrush, no rectal temps/suppositories; (3) Anemia: energy conservation, fall prevention, oxygen as needed.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-pancy-12", type: "question", question: "Fanconi anemia is:", options: ["An acquired condition", "An autosomal recessive inherited bone marrow failure syndrome with DNA repair defects, pancytopenia, congenital anomalies, and cancer predisposition", "A vitamin deficiency", "An autoimmune disorder"], correctIndex: 1, answer: "Fanconi anemia: inherited DNA repair deficiency (FA pathway genes) causing chromosomal instability. Presents in childhood with progressive pancytopenia, congenital anomalies (short stature, thumb/radial anomalies, cafe-au-lait spots), and dramatically increased cancer risk (AML, squamous cell carcinomas). Definitive treatment: stem cell transplant.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-pancy-13", type: "question", question: "Pancytopenia from B12 deficiency is caused by:", options: ["Bone marrow failure", "Impaired DNA synthesis in rapidly dividing bone marrow precursors, causing megaloblastic changes with large, immature, nonfunctional cells — all three cell lines are affected", "Autoimmune destruction", "Iron deficiency"], correctIndex: 1, answer: "Vitamin B12 is essential for DNA synthesis (thymidylate synthase pathway). Deficiency impairs DNA replication in rapidly dividing cells, including all bone marrow precursors. Cells grow (RNA/protein synthesis continues) but cannot divide (DNA synthesis impaired), producing large, immature megaloblastic cells. All three cell lines are affected.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-14", type: "question", question: "Eltrombopag and romiplostim are used in refractory pancytopenia because:", options: ["They replace blood cells", "They are thrombopoietin receptor agonists that stimulate bone marrow production — eltrombopag also has trilineage stimulatory effects in aplastic anemia", "They suppress the immune system", "They chelate iron"], correctIndex: 1, answer: "TPO receptor agonists stimulate megakaryopoiesis (platelet production). Eltrombopag additionally stimulates hematopoietic stem cell proliferation through c-Mpl signaling, improving all three cell lines in refractory aplastic anemia. It has shown significant trilineage responses even in patients who failed immunosuppressive therapy.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-pancy-15", type: "question", question: "The nurse teaching a patient with pancytopenia about infection prevention should emphasize:", options: ["Normal hygiene is sufficient", "Meticulous hand hygiene, avoid crowds and sick contacts, report ANY fever (even low-grade 38.0°C/100.4°F) immediately, no fresh produce unless thoroughly washed, and daily mouth care", "Only wash hands before meals", "Infection risk is not a concern"], correctIndex: 1, answer: "Neutropenic patients cannot mount a normal inflammatory response — infection can progress to sepsis rapidly without typical warning signs (no pus, minimal redness/swelling). Fever may be the ONLY sign of serious infection. Teaching: hand hygiene, food safety (no raw foods), oral care, avoid crowds, report fever/chills immediately.", category: "Hematology", difficulty: 1, clinicalPearl: "The neutropenic diet has fallen out of favor — emphasis is now on safe food handling rather than restricting fresh produce categories." },
  { id: "rn-patho-oa-7", type: "question", question: "Heberden nodes are characteristic of osteoarthritis and are found at:", options: ["Proximal interphalangeal joints", "Distal interphalangeal (DIP) joints — they are bony enlargements from osteophyte formation at the DIP joints", "Metacarpophalangeal joints", "Wrist joints"], correctIndex: 1, answer: "Heberden nodes = bony enlargements (osteophytes) at the DIP joints. Bouchard nodes = bony enlargements at the PIP joints. Both are classic OA findings. The distinction from RA: OA affects DIP joints (RA spares DIP), RA affects MCP and PIP joints symmetrically with soft tissue swelling, not bony nodes.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-8", type: "question", question: "The articular cartilage in osteoarthritis degenerates because:", options: ["Too much cartilage is produced", "Matrix metalloproteinases (MMPs) and aggrecanases break down the collagen-proteoglycan matrix faster than chondrocytes can repair it, leading to progressive cartilage loss", "Cartilage receives too much blood supply", "Immune cells attack the cartilage"], correctIndex: 1, answer: "OA pathogenesis: mechanical stress and inflammatory mediators upregulate catabolic enzymes (MMP-1, MMP-13, ADAMTS-4/5) in chondrocytes. These enzymes degrade type II collagen and aggrecan (the major cartilage structural components) faster than chondrocytes can synthesize replacements. The result is progressive cartilage thinning, fibrillation, and erosion.", category: "Musculoskeletal", difficulty: 3 },
  { id: "rn-patho-oa-9", type: "question", question: "Subchondral bone changes in OA include:", options: ["Bone softening", "Sclerosis (hardening), cyst formation, and osteophyte development — the bone remodels in response to altered mechanical loading from cartilage loss", "Normal bone structure", "Osteoporosis only"], correctIndex: 1, answer: "As cartilage erodes, subchondral bone is exposed to increased mechanical stress. It responds with: (1) sclerosis (increased bone density from reactive bone formation); (2) subchondral cysts (fluid-filled cavities from bone remodeling); (3) osteophytes (bony spurs at joint margins — the body's attempt to increase joint surface area and stability).", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-oa-10", type: "question", question: "OA joint stiffness differs from RA stiffness in that:", options: ["Both are identical", "OA stiffness lasts <30 minutes ('gelling') and improves with movement; RA morning stiffness lasts >60 minutes and is related to inflammatory synovitis", "OA stiffness lasts longer than RA", "OA stiffness is worse in the morning"], correctIndex: 1, answer: "OA gelling: brief stiffness (<30 minutes) after inactivity that resolves with movement. RA morning stiffness: prolonged (>60 minutes), related to synovial inflammation and edema that accumulate during sleep immobility. OA pain worsens with USE (weight-bearing), RA pain improves with USE (reducing synovial edema).", category: "Musculoskeletal", difficulty: 1, clinicalPearl: "Ask: 'How long are your joints stiff in the morning?' <30 min = OA, >60 min = inflammatory arthritis (RA, psoriatic, etc.)." },
  { id: "rn-patho-oa-11", type: "question", question: "Crepitus in OA is caused by:", options: ["Joint infection", "Roughened cartilage surfaces and bone-on-bone contact creating a grating or crunching sensation during joint movement", "Ligament tear", "Tendon inflammation"], correctIndex: 1, answer: "As articular cartilage deteriorates and becomes fibrillated, roughened surfaces grinding against each other during movement produce palpable and often audible crepitus. In advanced OA, complete cartilage loss leads to bone-on-bone contact, producing more pronounced crepitus with restricted range of motion.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-12", type: "question", question: "Viscosupplementation (hyaluronic acid injection) for OA works by:", options: ["Replacing cartilage", "Supplementing the decreased synovial fluid viscosity and volume with exogenous hyaluronic acid, providing lubrication and possibly anti-inflammatory effects", "Curing OA", "Strengthening muscles"], correctIndex: 1, answer: "Normal synovial fluid contains high-molecular-weight hyaluronic acid providing viscosity and shock absorption. In OA, synovial fluid HA concentration decreases and HA molecular weight drops, reducing its viscoelastic properties. Viscosupplementation restores some of these properties. Benefits are modest and temporary (6-12 months).", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-oa-13", type: "question", question: "Weight reduction in OA management is critical because:", options: ["It has no effect on joints", "Every pound of body weight translates to 3-4 pounds of force across the knee joint — even modest weight loss (10-15 lbs) significantly reduces joint loading and pain", "Weight only affects appearance", "Weight loss worsens OA"], correctIndex: 1, answer: "Biomechanical studies show that each pound of body weight creates 3-4 pounds of force across the knee during walking, and 6-8 times body weight during stair climbing. A 10-pound weight loss reduces knee joint force by 30-40 pounds per step. Weight loss also reduces systemic inflammatory adipokines that contribute to cartilage degradation.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-14", type: "question", question: "First-line pharmacologic treatment for OA is:", options: ["Opioids", "Acetaminophen for mild pain; topical NSAIDs for localized symptoms; oral NSAIDs (lowest effective dose, shortest duration) for moderate-severe pain", "Corticosteroids daily", "Disease-modifying agents"], correctIndex: 1, answer: "OA treatment ladder: (1) non-pharmacologic first (exercise, weight loss, physical therapy); (2) acetaminophen for mild pain; (3) topical NSAIDs (diclofenac gel — lower systemic risk); (4) oral NSAIDs (lowest effective dose, shortest duration — GI, renal, cardiovascular risks); (5) intra-articular corticosteroid injections; (6) duloxetine for chronic pain; (7) surgery.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-15", type: "question", question: "Inflammatory mediators in OA include:", options: ["Only in RA, not OA", "IL-1β, TNF-α, and IL-6 are present in OA synovium and cartilage — OA has a significant inflammatory component despite being traditionally classified as 'non-inflammatory'", "No inflammation occurs in OA", "Only prostaglandins"], correctIndex: 1, answer: "Modern understanding: OA has a significant inflammatory component. Damaged cartilage and synovium release IL-1β, TNF-α, IL-6, and prostaglandins. These pro-inflammatory mediators upregulate MMPs, inhibit cartilage repair, cause synovitis, and contribute to pain sensitization. OA is no longer considered purely 'wear and tear.'", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-oa-16", type: "question", question: "X-ray findings in osteoarthritis characteristically show:", options: ["Erosions and periarticular osteopenia (RA pattern)", "Joint space narrowing, subchondral sclerosis, osteophytes, and subchondral cysts — these are the four classic radiographic features of OA", "Normal joint spaces", "Soft tissue swelling only"], correctIndex: 1, answer: "The four hallmark radiographic features of OA: (1) joint space narrowing (from cartilage loss — may be asymmetric); (2) subchondral sclerosis (increased bone density from reactive bone formation); (3) osteophytes (bony spurs at joint margins); (4) subchondral cysts. Unlike RA, OA does NOT show erosions or periarticular osteopenia.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-17", type: "question", question: "Total joint replacement is indicated for OA when:", options: ["At initial diagnosis", "Conservative management fails, pain significantly impairs function and quality of life, and radiographic evidence shows severe joint destruction", "For any joint stiffness", "Only for patients under 50"], correctIndex: 1, answer: "Joint replacement indications: (1) severe pain unresponsive to conservative measures (medications, physical therapy, injections); (2) significant functional limitation (inability to walk, climb stairs, perform ADLs); (3) radiographic evidence of advanced joint destruction; (4) patient is healthy enough for surgery and committed to rehabilitation.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-diabetes-26", type: "question", question: "Diabetic ketoacidosis develops in T1DM but rarely in T2DM because:", options: ["T2DM patients don't eat carbohydrates", "T2DM patients retain enough residual insulin to suppress lipolysis and ketogenesis, even when blood glucose is elevated from insulin resistance", "T2DM patients exercise more", "DKA occurs equally in both types"], correctIndex: 1, answer: "In T2DM, the beta cells are still producing insulin (the problem is resistance, not absence). Even small amounts of insulin are sufficient to suppress hormone-sensitive lipase in adipose tissue, preventing excessive lipolysis and subsequent hepatic ketogenesis. T1DM has ABSOLUTE insulin deficiency, removing this brake on ketogenesis.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-27", type: "question", question: "Metformin's primary mechanism of action is:", options: ["Stimulating insulin secretion", "Decreasing hepatic glucose production by activating AMPK, and improving peripheral insulin sensitivity — it does NOT cause hypoglycemia as monotherapy", "Blocking carbohydrate absorption", "Increasing pancreatic insulin output"], correctIndex: 1, answer: "Metformin activates AMPK (AMP-activated protein kinase), which: (1) suppresses hepatic gluconeogenesis (primary effect — reducing fasting glucose); (2) improves skeletal muscle glucose uptake; (3) decreases intestinal glucose absorption. It does NOT stimulate insulin secretion, so hypoglycemia risk is minimal with monotherapy.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-28", type: "question", question: "GLP-1 receptor agonists (semaglutide, liraglutide) benefit T2DM patients by:", options: ["Replacing insulin", "Enhancing glucose-dependent insulin secretion, suppressing glucagon, delaying gastric emptying, and promoting satiety — leading to weight loss and improved glycemic control", "Increasing liver glucose output", "Blocking insulin receptors"], correctIndex: 1, answer: "GLP-1 RAs mimic the incretin hormone GLP-1: (1) augment insulin secretion (only when glucose is elevated — glucose-dependent, reducing hypoglycemia risk); (2) suppress glucagon; (3) delay gastric emptying; (4) promote satiety via central appetite suppression. These result in weight loss (3-15%) and HbA1c reduction (1-1.8%).", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-29", type: "question", question: "Insulin resistance in T2DM at the cellular level involves:", options: ["Destruction of beta cells", "Defective insulin receptor signaling — post-receptor defects (IRS phosphorylation, PI3K/Akt pathway impairment) reduce GLUT4 transporter translocation to the cell surface", "Absence of insulin receptors", "Excessive GLUT4 activity"], correctIndex: 1, answer: "In T2DM, insulin binds to its receptor but downstream signaling is impaired: (1) serine phosphorylation of IRS-1 (instead of tyrosine — caused by inflammatory mediators, lipid metabolites); (2) reduced PI3K/Akt pathway activation; (3) decreased GLUT4 translocation to the plasma membrane; (4) result: glucose cannot enter muscle/adipose cells despite adequate insulin.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-diabetes-30", type: "question", question: "Diabetic nephropathy progresses through which stages?", options: ["Sudden renal failure", "Hyperfiltration → microalbuminuria → macroalbuminuria → declining GFR → end-stage renal disease — early detection of microalbuminuria allows intervention with ACE inhibitors/ARBs", "Only causes UTIs", "Does not affect kidney function"], correctIndex: 1, answer: "Stage progression: (1) Hyperfiltration: increased GFR from hyperglycemia-induced afferent arteriolar dilation; (2) Microalbuminuria: UACR 30-300 mg/g (earliest detectable marker); (3) Overt proteinuria: UACR >300 mg/g; (4) Declining GFR; (5) ESRD. ACE inhibitors/ARBs at the microalbuminuria stage slow progression by reducing intraglomerular pressure.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-31", type: "question", question: "Metabolic syndrome increases T2DM risk and includes:", options: ["Only elevated blood sugar", "Central obesity, hypertriglyceridemia, low HDL, hypertension, and impaired fasting glucose — three of five criteria establish the diagnosis", "Only hypertension", "Normal lipid levels with elevated glucose"], correctIndex: 1, answer: "Metabolic syndrome (3 of 5 criteria): (1) waist circumference >40in (M) or >35in (F); (2) triglycerides ≥150; (3) HDL <40 (M) or <50 (F); (4) BP ≥130/85; (5) fasting glucose ≥100. Central obesity and insulin resistance are the core pathophysiologic drivers. Metabolic syndrome confers a 5x increased risk of developing T2DM.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-diabetes-32", type: "question", question: "SGLT2 inhibitors (empagliflozin, dapagliflozin) lower glucose by:", options: ["Stimulating insulin secretion", "Blocking glucose reabsorption in the proximal tubule, causing glycosuria — they also provide cardiovascular and renal protective benefits independent of glucose lowering", "Enhancing hepatic glucose uptake", "Blocking glucagon receptors"], correctIndex: 1, answer: "SGLT2 inhibitors block sodium-glucose cotransporter 2 in the proximal convoluted tubule, preventing reabsorption of approximately 70g/day of filtered glucose. This causes glycosuria (glucose in urine), lowering blood glucose. Additional benefits: reduced heart failure hospitalizations, renal protection, and modest weight loss/BP reduction.", category: "Endocrine", difficulty: 2, clinicalPearl: "Monitor for euglycemic DKA — a rare but serious complication where DKA occurs with near-normal glucose levels, making diagnosis delayed." },
  { id: "rn-patho-diabetes-33", type: "question", question: "The dawn phenomenon in diabetes is caused by:", options: ["Eating too much at dinner", "Early morning surge of counterregulatory hormones (growth hormone, cortisol) causing hyperglycemia — managed by adjusting evening insulin timing or dose", "Insulin excess at night", "Hypoglycemia rebound"], correctIndex: 1, answer: "Dawn phenomenon: normal physiologic surge of GH and cortisol in early morning (4-8 AM) causes hepatic gluconeogenesis and insulin resistance, raising fasting glucose. Unlike the Somogyi effect (rebound hyperglycemia from nocturnal hypoglycemia), dawn phenomenon has no preceding hypoglycemia. Check 3 AM glucose to differentiate.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-34", type: "question", question: "Diabetic peripheral neuropathy follows which pattern?", options: ["Random nerve involvement", "Symmetric 'stocking-glove' distribution starting distally — caused by polyol pathway activation and microvascular ischemia damaging nerve fibers", "Only affects motor nerves", "Only affects the face"], correctIndex: 1, answer: "Hyperglycemia activates the polyol pathway (glucose → sorbitol via aldose reductase), causing osmotic nerve damage. Additionally, microvascular ischemia of the vasa nervorum deprives nerves of oxygen. The longest nerves are affected first (feet/legs), producing the characteristic distal-to-proximal stocking-glove pattern of numbness, tingling, and burning pain.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-35", type: "question", question: "Honeymoon phase in T1DM refers to:", options: ["A permanent cure", "A temporary period after diagnosis where residual beta cell function allows reduced insulin requirements — it is NOT a cure and always ends as autoimmune destruction continues", "The time before diagnosis", "A dietary restriction period"], correctIndex: 1, answer: "After T1DM diagnosis and insulin initiation, beta cell rest and reduced glucotoxicity allow residual beta cells to temporarily improve function. Insulin requirements may decrease dramatically (some patients need very little insulin). This phase lasts weeks to months but ALWAYS ends as autoimmune destruction continues to completion.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-diabetes-36", type: "question", question: "Continuous glucose monitoring (CGM) measures:", options: ["Blood glucose directly", "Interstitial fluid glucose via a subcutaneous sensor — readings lag behind blood glucose by 5-15 minutes, which matters during rapid glucose changes", "Urine glucose", "HbA1c in real time"], correctIndex: 1, answer: "CGM sensors measure glucose in interstitial fluid, not blood. Interstitial glucose equilibrates with blood glucose but lags by 5-15 minutes. This lag is clinically significant during rapid glucose changes (exercise, meals, insulin administration). CGM provides trend arrows, alerts, and time-in-range data that HbA1c cannot capture.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-26", type: "question", question: "The osmotic diuresis in DKA causes:", options: ["Fluid retention", "Massive fluid losses (3-6L) through glucose-driven polyuria, depleting total body water, sodium, potassium, phosphorus, and magnesium", "Concentrated urine", "Decreased urine output"], correctIndex: 1, answer: "When blood glucose exceeds the renal threshold (approximately 180 mg/dL), glucose spills into urine. Glucose is osmotically active and drags water with it (osmotic diuresis), causing polyuria. This dehydration triggers polydipsia. Electrolytes (Na+, K+, PO4, Mg2+) are lost in the urine, causing total body depletion despite potentially normal serum levels.", category: "Endocrine", difficulty: 1, clinicalPearl: "Total body K+ is depleted even when serum K+ appears normal/high — acidosis shifts K+ out of cells, masking the deficit." },
  { id: "rn-patho-dka-27", type: "question", question: "Kussmaul respirations in DKA represent:", options: ["Anxiety hyperventilation", "Respiratory compensation for metabolic acidosis — deep, rapid breathing increases CO2 elimination to raise pH", "Airway obstruction", "Opioid overdose"], correctIndex: 1, answer: "Kussmaul respirations are deep, rapid, labored breaths that represent the respiratory system's attempt to compensate for severe metabolic acidosis. By increasing minute ventilation, CO2 elimination increases (driving the equation: CO2 + H2O ↔ H2CO3 ↔ H+ + HCO3- leftward), raising blood pH. The fruity acetone breath odor accompanies ketone exhalation.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-dka-28", type: "question", question: "IV insulin drip in DKA should be continued until:", options: ["Blood glucose is normal", "The anion gap closes (<12 mEq/L), pH >7.30, bicarbonate >15-18 mEq/L, AND the patient can eat — glucose normalizes before acidosis resolves, so add dextrose to fluids when glucose reaches 200-250 mg/dL", "Ketones are absent in urine", "12 hours have passed"], correctIndex: 1, answer: "Critical concept: blood glucose normalizes HOURS before ketoacidosis resolves. Stopping insulin when glucose is normal allows continued ketone production and persistent acidosis. Add D5W to IV fluids when glucose reaches 200-250 mg/dL to prevent hypoglycemia while maintaining the insulin drip to clear ketones and close the anion gap.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-dka-29", type: "question", question: "Phosphate replacement in DKA is indicated when:", options: ["Always", "Serum phosphate <1.0 mg/dL or symptoms of hypophosphatemia (respiratory muscle weakness, rhabdomyolysis) develop — routine replacement is not recommended", "Never", "Only with renal failure"], correctIndex: 1, answer: "Like potassium, total body phosphate is depleted in DKA (urinary losses) but serum levels may appear normal initially. Insulin and correction of acidosis shift phosphate intracellularly, potentially unmasking severe hypophosphatemia. Clinical significance: phosphate is needed for ATP and 2,3-DPG production. Replace if <1.0 mg/dL or symptomatic.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-dka-30", type: "question", question: "Precipitating factors for DKA include the '5 I's':", options: ["None are recognized", "Infection, Insulin omission/insufficiency, Infarction (MI), Intoxication (drugs/alcohol), and Initial presentation of T1DM", "Only infection", "Only insulin omission"], correctIndex: 1, answer: "The 5 I's of DKA triggers: (1) Infection (most common — 30-50% of cases; pneumonia, UTI, sepsis); (2) Insulin omission/pump failure; (3) Infarction (MI, stroke, mesenteric ischemia); (4) Intoxication (cocaine, alcohol); (5) Initial presentation (new-onset T1DM). Identifying and treating the precipitant is essential for DKA resolution.", category: "Endocrine", difficulty: 1 },
  { id: "rn-patho-thyroid-26", type: "question", question: "Thyroid storm can be precipitated by:", options: ["Thyroid medication compliance", "Surgery, infection, trauma, DKA, iodinated contrast, or abrupt thionamide discontinuation in a patient with uncontrolled hyperthyroidism", "Hypothyroidism", "Calcium supplementation"], correctIndex: 1, answer: "Thyroid storm triggers in patients with pre-existing hyperthyroidism: (1) surgery (especially thyroid surgery without preoperative euthyroid preparation); (2) infection/sepsis; (3) trauma; (4) DKA/metabolic crisis; (5) iodinated contrast dye (iodine load); (6) abrupt cessation of antithyroid medications; (7) childbirth.", category: "Endocrine", difficulty: 2 },
  { id: "rn-patho-thyroid-27", type: "question", question: "The Burch-Wartofsky score is used to:", options: ["Diagnose hypothyroidism", "Clinically score the likelihood of thyroid storm using temperature, CNS effects, GI-hepatic dysfunction, heart rate, heart failure, and atrial fibrillation — ≥45 points = highly suggestive of thyroid storm", "Measure T4 levels", "Assess thyroid nodule malignancy risk"], correctIndex: 1, answer: "The Burch-Wartofsky Point Scale assigns weighted scores to clinical parameters: temperature (5-30 points), CNS effects (0-30), GI-hepatic dysfunction (0-20), tachycardia (0-25), heart failure (0-15), and atrial fibrillation (0-10). Score ≥45: highly suggestive of thyroid storm; 25-44: impending storm; <25: storm unlikely.", category: "Endocrine", difficulty: 3 },
  { id: "rn-patho-thyroid-28", type: "question", question: "Hydrocortisone is given in thyroid storm because:", options: ["It treats the thyroid", "It blocks peripheral T4-to-T3 conversion AND addresses the relative adrenal insufficiency caused by the hypermetabolic state exhausting cortisol reserves", "It reduces fever", "It is a beta-blocker"], correctIndex: 1, answer: "Hydrocortisone in thyroid storm serves dual purposes: (1) inhibits peripheral 5'-deiodinase, blocking T4→T3 conversion (reducing active thyroid hormone); (2) prevents/treats relative adrenal insufficiency — the massive hypermetabolic state increases cortisol demand beyond adrenal output capacity. Dose: hydrocortisone 100mg IV q8h.", category: "Endocrine", difficulty: 3, clinicalPearl: "Always give hydrocortisone before starting thionamides — adrenal crisis can be masked by thyroid storm symptoms." },
  { id: "rn-patho-thyroid-29", type: "question", question: "Active cooling in thyroid storm should use:", options: ["Aspirin for fever reduction", "External cooling measures (cooling blankets, ice packs, cold IV fluids) and acetaminophen — AVOID aspirin because it displaces T4 from thyroid-binding globulin, increasing FREE thyroid hormone levels", "Warm blankets", "No cooling is needed"], correctIndex: 1, answer: "Aspirin is CONTRAINDICATED in thyroid storm because it displaces T3 and T4 from thyroid-binding globulin (TBG), increasing free (active) thyroid hormone levels and potentially worsening the storm. Use acetaminophen for antipyresis and external cooling measures (cooling blankets, tepid sponging, ice packs to axillae/groin).", category: "Endocrine", difficulty: 2, clinicalPearl: "A common NCLEX pitfall: aspirin worsens thyroid storm despite being an antipyretic. Always choose acetaminophen." },
  { id: "rn-patho-thyroid-30", type: "question", question: "Agranulocytosis is a rare but life-threatening side effect of:", options: ["Beta-blockers", "Thionamides (PTU, methimazole) — presenting as sudden sore throat and high fever, requiring immediate CBC and drug discontinuation", "Iodine solutions", "Corticosteroids"], correctIndex: 1, answer: "Thionamide-induced agranulocytosis (ANC <500) occurs in 0.1-0.5% of patients, usually within the first 3 months. It presents suddenly with sore throat, fever, and oral ulcers. Teach patients: STOP the medication immediately and seek emergency care if fever/sore throat develop. Obtain stat CBC. Agranulocytosis is usually reversible with drug discontinuation.", category: "Endocrine", difficulty: 2, clinicalPearl: "Teach every patient starting PTU or methimazole: 'If you get a sore throat with fever, go to the ER immediately for a blood count.'" },
  { id: "rn-patho-ra-13", type: "question", question: "Rheumatoid arthritis is fundamentally different from OA because:", options: ["Both are the same", "RA is a systemic autoimmune disease attacking the synovial membrane (pannus formation), while OA is primarily degenerative cartilage loss from mechanical wear", "RA only affects joints", "OA is autoimmune"], correctIndex: 1, answer: "RA: autoimmune disease → CD4+ T cells and macrophages infiltrate the synovium → pannus (proliferative granulation tissue) forms → pannus invades and destroys cartilage and bone → systemic inflammation affects multiple organs. OA: mechanical wear → cartilage degradation → subchondral bone remodeling → primarily a local joint process.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-14", type: "question", question: "Pannus tissue in RA is:", options: ["Normal cartilage", "Abnormal proliferative synovial tissue that invades and erodes cartilage and bone — it contains inflammatory cells, fibroblasts, and angiogenic factors that perpetuate joint destruction", "Scar tissue from injury", "A type of bone spur"], correctIndex: 1, answer: "Pannus is the hallmark pathologic tissue of RA. It forms from proliferating synoviocytes, infiltrating immune cells (T cells, macrophages, B cells), fibroblasts, and new blood vessels. The pannus grows over the articular cartilage surface and invades both cartilage and subchondral bone, causing the characteristic erosive joint destruction of RA.", category: "Musculoskeletal", difficulty: 3 },
  { id: "rn-patho-ra-15", type: "question", question: "DMARDs (disease-modifying antirheumatic drugs) are started early in RA to:", options: ["Treat symptoms only", "Prevent irreversible joint erosion — joint damage begins within the first 2 years and cannot be reversed once it occurs", "Cure RA permanently", "Replace NSAIDs"], correctIndex: 1, answer: "Early aggressive DMARD therapy (within 3-6 months of diagnosis) is the standard of care because joint erosion begins within the first 1-2 years of disease. Once erosion occurs, it is irreversible. Methotrexate is the first-line DMARD. 'Window of opportunity': early treatment produces better long-term outcomes than delayed treatment.", category: "Musculoskeletal", difficulty: 1, clinicalPearl: "Treat-to-target: aim for remission or low disease activity within 6 months. If not achieved, escalate therapy." },
  { id: "rn-patho-ra-16", type: "question", question: "Methotrexate requires monitoring for:", options: ["No monitoring needed", "Hepatotoxicity (LFTs), myelosuppression (CBC), pulmonary toxicity (pneumonitis), and renal function — folic acid supplementation reduces side effects", "Only blood glucose", "Only blood pressure"], correctIndex: 1, answer: "Methotrexate monitoring: (1) CBC q1-3 months (myelosuppression — pancytopenia); (2) LFTs q1-3 months (hepatotoxicity — fibrosis/cirrhosis with chronic use); (3) renal function (methotrexate is renally cleared — accumulates in renal impairment); (4) pulmonary symptoms (pneumonitis — rare but potentially fatal). Folic acid 1mg daily reduces GI and hematologic toxicity.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-17", type: "question", question: "TNF-alpha inhibitors (adalimumab, etanercept, infliximab) for RA carry a risk of:", options: ["No significant risks", "Serious infections (especially reactivation of latent tuberculosis), infusion/injection reactions, and increased lymphoma risk — screen for TB before starting", "Liver failure only", "Kidney stones"], correctIndex: 1, answer: "TNF-α is a key cytokine for immune defense against intracellular pathogens. Blocking it increases risk of: (1) serious infections (TB reactivation — screen with PPD/IGRA before starting); (2) invasive fungal infections (histoplasmosis, coccidioidomycosis); (3) hepatitis B reactivation; (4) possible increased lymphoma risk. Avoid live vaccines during therapy.", category: "Musculoskeletal", difficulty: 2, clinicalPearl: "Mandatory TB screening before ALL biologic DMARDs. If latent TB positive, treat with isoniazid before starting the biologic." },
  { id: "rn-patho-ra-18", type: "question", question: "Morning stiffness lasting >60 minutes in RA is caused by:", options: ["Muscle weakness", "Overnight accumulation of inflammatory exudate in the synovium — synovial fluid volume increases during rest, causing joint swelling and stiffness that improves with movement", "Joint deformity", "Medication side effects"], correctIndex: 1, answer: "During sleep/immobility, inflammatory mediators accumulate in the synovium, increasing synovial fluid volume, edema, and joint capsule distension. Movement helps redistribute this fluid (mechanical pumping), reducing swelling and stiffness. RA morning stiffness >60 minutes distinguishes inflammatory arthritis from OA (<30 minutes).", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-ra-19", type: "question", question: "Extra-articular manifestations of RA include:", options: ["None — RA only affects joints", "Rheumatoid nodules, interstitial lung disease, pericarditis, scleritis, Felty syndrome (splenomegaly + neutropenia), and accelerated atherosclerosis", "Only skin rash", "Only fatigue"], correctIndex: 1, answer: "RA is a systemic disease. Extra-articular manifestations: (1) rheumatoid nodules (subcutaneous, over pressure points); (2) pulmonary (ILD, pleuritis, nodules); (3) cardiac (pericarditis, accelerated atherosclerosis — #1 cause of death in RA); (4) ocular (scleritis, keratoconjunctivitis sicca); (5) hematologic (Felty syndrome, anemia of chronic disease); (6) vasculitis.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-20", type: "question", question: "Swan neck and boutonniere deformities in RA are caused by:", options: ["Normal aging", "Chronic synovial inflammation destroying the joint capsule, tendons, and ligaments — leading to characteristic finger deformities from tendon imbalance", "Osteoarthritis", "Trauma"], correctIndex: 1, answer: "Chronic RA synovitis stretches and erodes tendons and ligaments: (1) Swan neck: PIP hyperextension + DIP flexion (from intrinsic muscle tightness and lateral band subluxation); (2) Boutonniere: PIP flexion + DIP hyperextension (from central slip disruption of the extensor mechanism). These are LATE findings of uncontrolled RA.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-21", type: "question", question: "Ulnar deviation in RA occurs at:", options: ["DIP joints", "MCP joints — chronic synovitis weakens the radial collateral ligaments, and the pull of flexor tendons causes fingers to drift toward the ulnar side", "Wrist joint", "Ankle joint"], correctIndex: 1, answer: "Ulnar deviation (ulnar drift) at the MCP joints is a classic RA deformity. Chronic MCP synovitis stretches and weakens the radial (lateral) collateral ligaments while extensor tendons sublux ulnarly. The mechanical advantage of the flexor tendons then pulls the fingers progressively toward the ulnar side. This is irreversible without surgical correction.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-22", type: "question", question: "RF (rheumatoid factor) and anti-CCP antibodies in RA diagnosis:", options: ["Are always positive", "Anti-CCP is MORE SPECIFIC (>95%) for RA than RF (which can be positive in many conditions) — double positivity confirms diagnosis and predicts more aggressive disease", "Have no diagnostic value", "Are only checked once"], correctIndex: 1, answer: "RF (IgM against IgG Fc): sensitive (60-80%) but NOT specific — positive in infections, other autoimmune diseases, and even healthy elderly. Anti-CCP (anti-cyclic citrullinated peptide): highly specific (>95%) for RA, often positive years before symptoms, and predicts erosive disease. Both positive = seropositive RA with worse prognosis.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-ra-23", type: "question", question: "Joint protection principles for RA patients include:", options: ["Using joints forcefully", "Using the largest joint possible for tasks, avoiding positions of deformity, distributing load across multiple joints, and using assistive devices to reduce joint stress", "Avoiding all movement", "Splinting all joints 24/7"], correctIndex: 1, answer: "Joint protection reduces mechanical stress on inflamed joints: (1) use large joints instead of small (push door open with hip, not hands); (2) distribute weight across multiple joints (carry with both hands); (3) avoid sustained grip or pinch; (4) use adaptive equipment (jar openers, built-up utensils); (5) maintain ROM but avoid overuse during flares.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-ra-24", type: "question", question: "Atlantoaxial subluxation in RA is dangerous because:", options: ["It causes hand pain", "C1-C2 instability from ligament erosion can compress the spinal cord, causing quadriparesis or sudden death — assess for neck pain and neurological symptoms before intubation", "It is a cosmetic issue", "It only affects the fingers"], correctIndex: 1, answer: "RA can erode the transverse ligament of C1 (atlas), which normally holds the odontoid process (dens) of C2 (axis) in place. Subluxation allows the dens to compress the cervical spinal cord. Flexion cervical X-ray (atlantodental interval >3mm = subluxation). Critical: evaluate before ANY intubation or procedure requiring neck manipulation.", category: "Musculoskeletal", difficulty: 3, clinicalPearl: "NCLEX tip: always assess cervical spine stability in RA patients before surgery/intubation. Failure to identify C1-C2 instability can cause fatal cord compression." },
  { id: "rn-patho-pancy-16", type: "question", question: "Pancytopenia from hypersplenism occurs because:", options: ["The spleen produces blood cells", "An enlarged spleen excessively sequesters and destroys all blood cell types — removing more cells from circulation than the marrow can replace", "The spleen stops working", "Bone marrow fails"], correctIndex: 1, answer: "Hypersplenism: splenomegaly (from cirrhosis, lymphoma, infections) causes increased trapping and destruction of blood cells within the splenic red pulp. All three cell lines are affected because the spleen filters RBCs, platelets, and WBCs. Treatment addresses the underlying cause; severe cases may require splenectomy.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-17", type: "question", question: "Pancytopenic patients with petechiae and gum bleeding have:", options: ["Normal platelet function", "Thrombocytopenia — the bleeding risk requires fall prevention, soft toothbrush, electric razor, no aspirin/NSAIDs, no IM injections, and platelet transfusion if <10,000 or actively bleeding", "Vitamin C deficiency only", "DIC always"], correctIndex: 1, answer: "Petechiae and mucosal bleeding indicate platelet counts typically <20,000-50,000. Nursing interventions: (1) fall prevention (avoid trauma); (2) soft toothbrush (prevent gum bleeding); (3) electric razor only (no cuts); (4) avoid aspirin/NSAIDs (impair remaining platelet function); (5) no rectal temps/suppositories; (6) apply prolonged pressure to venipuncture sites.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-pancy-18", type: "question", question: "Paroxysmal nocturnal hemoglobinuria (PNH) causes pancytopenia through:", options: ["Iron deficiency", "Complement-mediated destruction of blood cells lacking GPI-anchored protective proteins (CD55, CD59) — treated with eculizumab (complement C5 inhibitor)", "Vitamin B12 deficiency", "Autoimmune attack on bone marrow"], correctIndex: 1, answer: "PNH: acquired clonal stem cell mutation in the PIGA gene → deficiency of GPI-anchored proteins (CD55/DAF and CD59/MIRL) on blood cell surfaces → these proteins normally protect against complement-mediated lysis → unprotected cells are destroyed by the terminal complement complex (MAC). Eculizumab blocks C5 cleavage, preventing MAC formation.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-pancy-19", type: "question", question: "Iron studies in pancytopenia evaluation help distinguish:", options: ["Nothing useful", "Iron deficiency anemia from thalassemia trait and anemia of chronic disease — ferritin, serum iron, TIBC, and transferrin saturation patterns differ for each cause", "Only liver disease", "Only kidney disease"], correctIndex: 1, answer: "Iron study patterns: (1) Iron deficiency: low ferritin, low serum iron, HIGH TIBC, low transferrin saturation; (2) Thalassemia trait: normal/high ferritin, normal/high serum iron, normal TIBC; (3) Anemia of chronic disease: high ferritin (acute phase reactant), low serum iron, LOW TIBC, low transferrin saturation. Ferritin is the most useful single test.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-oa-18", type: "question", question: "OA differs from RA in joint involvement pattern:", options: ["Both affect the same joints", "OA affects weight-bearing joints (knees, hips, spine) and DIP joints; RA symmetrically affects MCP, PIP, and wrists while SPARING DIP joints", "OA affects MCP joints primarily", "RA affects DIP joints primarily"], correctIndex: 1, answer: "Joint involvement pattern is a key differentiator: OA → weight-bearing joints (knees > hips > lumbar spine > cervical spine), DIP and PIP joints (Heberden/Bouchard nodes), first CMC joint (base of thumb). RA → MCP joints, PIP joints, wrists, MTPs (bilateral symmetric). RA typically SPARES DIP joints and lumbar spine.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-19", type: "question", question: "Synovial inflammation in OA is:", options: ["Absent — OA is purely mechanical", "Present but SECONDARY to cartilage degradation — cartilage breakdown products trigger synovial inflammation, contributing to pain and further cartilage damage in a vicious cycle", "The primary pathology as in RA", "Only occurs after surgery"], correctIndex: 1, answer: "Modern understanding: OA has significant synovitis. Cartilage degradation releases matrix fragments (collagen, aggrecan) into the joint space. These fragments activate synovial macrophages via pattern recognition receptors (toll-like receptors), triggering inflammatory cytokine production (IL-1β, TNF-α, IL-6). This synovitis exacerbates cartilage destruction — a positive feedback loop.", category: "Musculoskeletal", difficulty: 3 },
  { id: "rn-patho-oa-20", type: "question", question: "Duloxetine is used for OA pain because:", options: ["It is an NSAID", "It is a serotonin-norepinephrine reuptake inhibitor (SNRI) that modulates central pain processing — approved for chronic musculoskeletal pain including OA", "It builds cartilage", "It reduces inflammation locally"], correctIndex: 1, answer: "Duloxetine modulates descending inhibitory pain pathways by increasing serotonin and norepinephrine in the CNS. Chronic OA pain involves central sensitization (amplified pain processing in the spinal cord and brain). Duloxetine addresses this central component, providing analgesia independent of peripheral inflammation. FDA-approved for chronic musculoskeletal pain.", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-oa-21", type: "question", question: "Crepitus on physical examination of an OA joint indicates:", options: ["Joint infection", "Roughened cartilage surfaces or bone-on-bone contact during movement — a palpable and often audible grating sensation confirming cartilage loss", "Normal joint function", "Ligament laxity"], correctIndex: 1, answer: "Crepitus is a hallmark physical finding of OA. As cartilage fibrillates and erodes, the previously smooth gliding surfaces become rough. Movement produces a grating sensation (palpable and audible). Fine crepitus suggests early cartilage changes; coarse crepitus suggests advanced cartilage loss with near bone-on-bone contact.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-22", type: "question", question: "Obesity increases OA risk through both:", options: ["Only one mechanism", "Mechanical overloading of weight-bearing joints AND metabolic inflammation from adipokines (leptin, IL-6, TNF-α) that directly degrade cartilage — explaining why hand OA is also more common in obese patients", "Decreased activity only", "Genetic changes only"], correctIndex: 1, answer: "Obesity contributes to OA through dual pathways: (1) biomechanical — increased joint loading (3-4x body weight at the knee per step); (2) metabolic — adipose tissue produces pro-inflammatory adipokines (leptin, resistin, IL-6, TNF-α) that systemically promote cartilage degradation. The metabolic pathway explains increased hand OA in obesity (non-weight-bearing joints).", category: "Musculoskeletal", difficulty: 2 },
  { id: "rn-patho-oa-23", type: "question", question: "Chondroitin and glucosamine for OA:", options: ["Are proven to rebuild cartilage", "Have inconsistent evidence — some studies show modest pain benefit comparable to placebo, while others show no benefit; they are not recommended as first-line by current guidelines", "Are contraindicated", "Require a prescription"], correctIndex: 1, answer: "Large RCTs (GAIT trial, LEGS study) showed mixed results: some participants reported modest pain improvement, but effects were often not significantly different from placebo. Current ACR/EULAR guidelines do not recommend them as first-line treatment. They are generally safe as supplements but should not replace evidence-based therapies.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-24", type: "question", question: "Total joint replacement is most commonly performed for:", options: ["Young athletes with minor injury", "End-stage OA where conservative management has failed, pain significantly limits daily function, and radiographs confirm severe joint destruction", "Early OA with mild symptoms", "Any joint stiffness"], correctIndex: 1, answer: "TJR indications: (1) severe pain refractory to conservative management (medications, PT, injections); (2) significant functional limitation (cannot walk, climb stairs, perform ADLs); (3) radiographic evidence of advanced joint destruction (bone-on-bone). Patient must be medically fit for surgery and committed to postoperative rehabilitation.", category: "Musculoskeletal", difficulty: 1 },
  { id: "rn-patho-oa-25", type: "question", question: "Post-TKR DVT prevention includes:", options: ["Bedrest for 2 weeks", "Pharmacologic anticoagulation (LMWH, DOACs, or aspirin) PLUS mechanical prophylaxis (SCDs, early mobilization within 24 hours) for 10-35 days", "NSAIDs only", "No intervention needed"], correctIndex: 1, answer: "TJR has high DVT/PE risk. Prevention requires BOTH pharmacologic (enoxaparin, rivaroxaban, apixaban, or aspirin) AND mechanical (SCDs, TED hose, early ambulation within 24 hours). Duration: minimum 10-14 days post-surgery. Some guidelines recommend 35 days for total hip arthroplasty. Early mobilization is the most important non-pharmacologic intervention.", category: "Musculoskeletal", difficulty: 1, clinicalPearl: "Post-TKR hip precautions are for THR, not TKR. TKR patients focus on ROM and strengthening." },
  { id: "rn-patho-thal-18", type: "question", question: "Cardiac MRI T2* is used in thalassemia to:", options: ["Diagnose thalassemia type", "Quantify cardiac iron loading — T2* <20ms indicates iron overload, <10ms indicates severe cardiac risk requiring urgent intensified chelation", "Measure hemoglobin levels", "Assess bone marrow cellularity"], correctIndex: 1, answer: "T2* MRI exploits the paramagnetic properties of iron deposits in tissues. Iron causes faster signal decay (shorter T2* values). Cardiac T2*: >20ms = normal; 10-20ms = moderate iron overload (increase chelation); <10ms = severe cardiac iron overload (high risk of heart failure/arrhythmia — urgent intensified chelation). This non-invasive method guides chelation therapy.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-thal-19", type: "question", question: "Splenectomy in thalassemia is considered when:", options: ["At diagnosis", "Transfusion requirements increase significantly (hypersplenism) — the enlarged spleen traps and destroys transfused RBCs, increasing transfusion burden and iron loading", "For all thalassemia patients", "To treat iron overload"], correctIndex: 1, answer: "Hypersplenism in thalassemia: the chronically enlarged spleen increasingly sequesters and destroys RBCs, raising transfusion requirements. Splenectomy indicators: transfusion requirements >200-250 mL/kg/year of PRBCs, or >50% increase over baseline. Post-splenectomy: lifelong infection risk requiring vaccinations and monitoring.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-thal-20", type: "question", question: "Gene therapy for beta-thalassemia works by:", options: ["Replacing the spleen", "Inserting a functional β-globin gene into the patient's own hematopoietic stem cells using a lentiviral vector, then reinfusing them after myeloablative conditioning", "Giving regular transfusions", "Administering growth factors"], correctIndex: 1, answer: "Betibeglogene autotemcel (Zynteglo): (1) collect patient's HSCs via apheresis; (2) transduce with lentiviral vector carrying functional β-globin gene; (3) myeloablative conditioning (busulfan) to eliminate defective marrow; (4) reinfuse modified HSCs. The engrafted cells produce functional β-globin, reducing or eliminating transfusion dependence. FDA-approved 2022.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-sickle-20", type: "question", question: "Stroke prevention in children with SCD requires:", options: ["No screening", "Annual transcranial Doppler (TCD) screening starting at age 2 — velocities >200 cm/sec indicate high stroke risk, managed with chronic transfusion to keep HbS <30%", "Aspirin therapy", "Only treating after a stroke occurs"], correctIndex: 1, answer: "SCD cerebral vasculopathy causes progressive large-vessel stenosis. TCD detects elevated flow velocities from narrowed arteries. Velocities >200 cm/sec = high risk (10%/year stroke risk without intervention). Chronic transfusion therapy (target HbS <30%) reduces stroke risk by 92%. Continue indefinitely or transition to hydroxyurea in select patients.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-sickle-21", type: "question", question: "Delayed hemolytic transfusion reaction in SCD is dangerous because:", options: ["It is mild", "The patient's immune system destroys BOTH the donor RBCs AND their own RBCs (hyperhemolysis), causing hemoglobin to drop BELOW pre-transfusion levels", "It only affects donor cells", "It always resolves spontaneously"], correctIndex: 1, answer: "Hyperhemolysis syndrome: SCD patients with alloantibodies can develop bystander hemolysis where the immune response destroys both donor AND autologous RBCs. Hemoglobin drops precipitously below pre-transfusion baseline. Reticulocyte count may be suppressed. Further transfusion can WORSEN the hemolysis. Treatment: corticosteroids, IVIG, eculizumab. Avoid additional transfusion if possible.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-pancy-20", type: "question", question: "Hairy cell leukemia can cause pancytopenia by:", options: ["Bone marrow aplasia", "Infiltrating the bone marrow and spleen with malignant B cells that have characteristic 'hairy' cytoplasmic projections — treated effectively with cladribine (purine analog) with >90% response rate", "Vitamin deficiency", "Autoimmune destruction"], correctIndex: 1, answer: "Hairy cell leukemia: rare chronic B-cell leukemia with distinctive cytoplasmic projections. Malignant cells infiltrate bone marrow (causing pancytopenia) and spleen (splenomegaly). Diagnosis: flow cytometry (CD25+, CD103+, CD123+, annexin A1+), TRAP stain positive. Treatment: single course of cladribine achieves complete remission in >80% of patients.", category: "Hematology", difficulty: 3 },
  { id: "rn-patho-pancy-21", type: "question", question: "The nurse's teaching priority for a patient with newly diagnosed pancytopenia includes:", options: ["No specific teaching needed", "Recognizing and reporting signs of bleeding (bruising, petechiae, blood in stool/urine), infection (fever — even low-grade), and severe anemia (dyspnea, chest pain, extreme fatigue)", "Only dietary counseling", "Exercise recommendations only"], correctIndex: 1, answer: "Triple-threat teaching for pancytopenia: (1) BLEEDING — report new bruising, petechiae, melena, hematuria, heavy menstruation, prolonged bleeding from cuts; (2) INFECTION — report ANY fever ≥100.4°F, chills, sore throat, cough, burning urination (may be the ONLY sign in neutropenia); (3) ANEMIA — report increasing fatigue, dyspnea, chest pain, dizziness.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-pancy-22", type: "question", question: "ATG (anti-thymocyte globulin) plus cyclosporine is used for aplastic anemia to:", options: ["Stimulate bone marrow directly", "Suppress the autoimmune T-cell attack on hematopoietic stem cells — this is the first-line treatment for patients without an HLA-matched sibling donor", "Chelate iron", "Prevent infection"], correctIndex: 1, answer: "Most acquired aplastic anemia is autoimmune — activated T cells attack and destroy hematopoietic stem cells. ATG depletes these pathogenic T cells, while cyclosporine provides ongoing immunosuppression. Combined response rate: 60-70%. Used when stem cell transplant is not feasible (no matched donor, age >40). Monitor for serum sickness after ATG.", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-23", type: "question", question: "Platelet transfusion in pancytopenia is typically given when:", options: ["Platelets are <100,000", "Platelets are <10,000 (prophylactic) OR the patient has active bleeding with platelets <50,000 — each unit should raise count by 5,000-10,000/μL", "Platelets are <200,000", "Only with surgical bleeding"], correctIndex: 1, answer: "Platelet transfusion thresholds: (1) <10,000 — prophylactic transfusion (spontaneous intracranial hemorrhage risk); (2) <20,000 with fever or active minor bleeding; (3) <50,000 for invasive procedures or active significant bleeding; (4) <100,000 for neurosurgery. One apheresis unit or 6 pooled units should raise count by 30,000-50,000.", category: "Hematology", difficulty: 1 },
  { id: "rn-patho-pancy-24", type: "question", question: "G-CSF (filgrastim) in pancytopenia is used to:", options: ["Replace all blood cells", "Stimulate neutrophil production specifically — it promotes granulocyte colony-forming unit proliferation and maturation, reducing the duration and severity of neutropenia", "Stimulate platelet production", "Treat anemia"], correctIndex: 1, answer: "G-CSF (granulocyte colony-stimulating factor) binds to G-CSF receptors on neutrophil precursors, stimulating proliferation and differentiation. It reduces the depth and duration of neutropenia after chemotherapy. Side effects: bone pain (marrow expansion), splenic enlargement (rare rupture). Not effective in aplastic anemia (insufficient stem cells to stimulate).", category: "Hematology", difficulty: 2 },
  { id: "rn-patho-pancy-25", type: "question", question: "The Mentzer index helps differentiate:", options: ["AML from ALL", "Iron deficiency anemia from thalassemia trait in microcytic anemia — MCV/RBC ratio >13 suggests iron deficiency, <13 suggests thalassemia trait", "Aplastic anemia from MDS", "Acute from chronic anemia"], correctIndex: 1, answer: "Mentzer index = MCV ÷ RBC count. In iron deficiency: MCV is low but RBC count is also low → ratio >13. In thalassemia trait: MCV is low but RBC count is normal or elevated (many small cells) → ratio <13. This simple calculation helps guide initial workup of microcytic anemia and prevents inappropriate iron supplementation in thalassemia.", category: "Hematology", difficulty: 2, clinicalPearl: "Quick rule: >13 = Iron deficiency; <13 = Thalassemia trait. Confirm with iron studies and Hgb electrophoresis." },
  { id: "rn-patho-osteo-13", type: "question", question: "Calcium and vitamin D supplementation for osteoporosis prevention:", options: ["Is unnecessary if taking bisphosphonates", "Provides the building blocks for bone mineralization — calcium 1,000-1,200 mg/day and vitamin D 800-1,000 IU/day are recommended alongside any pharmacologic therapy", "Replaces the need for exercise", "Only needed in children"], correctIndex: 1, answer: "Adequate calcium and vitamin D are foundational for any osteoporosis treatment plan. Without sufficient calcium substrate and vitamin D (for intestinal calcium absorption), even the most effective osteoporosis medications cannot optimize bone mineralization. Preferred source: dietary calcium (dairy, leafy greens) supplemented as needed. Check 25-OH vitamin D levels.", category: "Musculoskeletal", difficulty: 1, clinicalPearl: "Calcium supplements should be taken in divided doses (≤500mg per dose) for optimal absorption. Calcium citrate is preferred in patients on PPIs." },
  { id: "rn-patho-osteo-14", type: "question", question: "Denosumab for osteoporosis works by:", options: ["Stimulating osteoblasts directly", "Inhibiting RANKL — blocking osteoclast formation, function, and survival, thereby reducing bone resorption", "Providing calcium directly", "Blocking vitamin D receptors"], correctIndex: 1, answer: "Denosumab (Prolia) is a monoclonal antibody against RANKL (receptor activator of nuclear factor kappa-B ligand). RANKL is essential for osteoclast differentiation, activation, and survival. By blocking RANKL, denosumab profoundly inhibits bone resorption. Given SQ every 6 months. Unlike bisphosphonates, it does not accumulate in bone — effects reverse upon discontinuation (rebound bone loss risk).", category: "Musculoskeletal", difficulty: 2, clinicalPearl: "Denosumab must NOT be stopped abruptly — rebound vertebral fractures can occur. Transition to a bisphosphonate after discontinuing denosumab." }
];
